window.__dh_data["th"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "ธรรมบท",
  "chaps": "บท",
  "fontsize": "ขนาดตัวอักษร",
  "chap1": "คู่",
  "1": "ใจเป็นผู้นำสรรพสิ่ง ใจเป็นใหญ่ (กว่าสรรพสิ่ง) สรรพสิ่งสำเร็จได้ด้วยใจ ถ้าพูดหรือทำสิ่งใดด้วยใจชั่ว ความทุกข์ย่อมติดตามตัวเขา เหมือนล้อหมุนเต้าตามเท้าโค",
  "2": "ใจเป็นผู้นำสรรพสิ่ง ใจเป็นใหญ่ (กว่าสรรพสิ่ง) ถ้าพูดหรือทำสิ่งใดด้วยใจบริสุทธิ์ ความสุขย่อมติดตามเขา เหมือนเงาติดตามตน",
  "3": "ใครมัวคิดอาฆาตว่า 'มันด่าเรา มันทำร้ายเรา มันเอาชนะเรา มันขโมยของเรา' เวรของเขาไม่มีทางระงับ",
  "4": "ใครไม่คิดอาฆาตว่า 'มันด่าเรา มันทำร้ายเรา มันเอาชนะเรา มันขโมยของเรา' เวรของเขาย่อมระงับ",
  "5": "แต่ไหนแต่ไรมา ในโลกนี้ เวรไม่มีระงับด้วยการจองเวร มีแต่ระงับด้วยการไม่จองเวร นี้เป็นกฎเกณฑ์ตายตัว",
  "6": "คนทั่วไปมักนึกไม่ถึงว่า ตนกำลังพินาศ เพราะวิวาททุ่มเถึยงกัน ส่วนผู้รู้ความจริงเช่นนั้น ย่อมไม่ทะเลาะกันอีกต่อไป",
  "7": "มารย่อมสามารถทำลายบุคคล ผู้ตกเป็นทาสของความสวยงาม ไม่ควบคุมการแสดงออก ไม่รู้ประมาณในโภชนาหาร เกียจคร้านและอ่อนแอ เหมือนลมแรงพัดโค่นต้นไม้ที่ไม่แข็งแรง",
  "8": "มารย่อมไม่สามารถทำลายบุคคล ผู้ไม่ตกเป็นทาสของความสวยงาม รูจักควบคุมการแสดงออก รู้ประมาณในโภชนาหาร มีศรัทธา และมีความขยันหมั่นเพียร เหมือนลมไม่สามารถพัดโค่นภูเขา",
  "9": "คนที่กิเลสครอบงำใจ ไร้การบังคับตนเองและไร้สัตย์ ถึงจะครองผ้ากาสาวพัสตร์ ก็หาคู่ควรไม่",
  "10": "ผู้หมดกิเลสแล้ว มั่นคงในศีล รู้จักบังคับตนเอง และมีสัตย์ ควรครองผ้ากาสาวพัสตร์แท้จริง",
  "11": "ผู้ใดเห็นสิ่งที่ไม่เป็นสาระ ว่าเป็นสาระ เห็นสิ่งที่เป็นสาระ ว่าไร้สาระ ผู้นั้นมีความคิดผิดเสียแล้ว ย่อมไม่ประสบสิ่งที่เป็นสาระ",
  "12": "ผู้ที่เข้าใจสิ่งที่เป็นสาระ ว่าเป็นสาระ และสิ่งที่ไร้สาระว่าไร้สาระ มีความคิดเห็นชอบ ย่อมประสบสิ่งที่เป็นสาระ",
  "13": "เรือนที่มุงไม่เรียบร้อย ฝนย่อมไหลย้อยเข้าได้ ใจที่ไม่อบรมฝึกหัด ราคะกำหนัดย่อมครอบงำ",
  "14": "เรือนที่มุงเรียบร้อย ฝนย่อมไหลย้อยเข้าไม่ได้ ใจที่อบรมเป็นอย่างดี ราคะไม่มีวันเข้าครอบงำ",
  "15": "คนทำชั่วย่อมเศร้าโศกในโลกนี้ คนทำชั่วย่อมเศร้าโศกในโลกหน้า คนทำชั่วย่อมเศร้าโศกในโลกทั้งสอง คนทำชั่วย่อมเศร้าโศกเดือดร้อนยิ่งนัก เมื่อมองเห็นแต่กรรมชั่วของตน",
  "16": "คนทำดีย่อมร่าเริงในโลกนี้ คนทำดีย่อมร่าเริงในโลกหน้า คนทำดีย่อมร่าเริงในโลกทั้งสอง คนทำดีย่อมร่าเริง เบิกบานใจยิ่งนัก เมื่อมองเห็นแต่กรรมบริสุทธิ์ของตน",
  "17": "คนทำชั่วย่อมเดือดร้อน ใน โลกนี้ คนทำชั่วย่อมเดือดร้อนในโลกหน้า คนทำชั่ว ย่อมเดือดร้อนในโลกทั้งสอง เมื่อคิดได้ว่า ตนทำแต่กรรมชั่ว ตายไปเกิดในทุคติ ยี่งเดือดร้อนหนักขึ้น",
  "18": "คนทำดีย่อมสุขใจในโลกนี้ คนทำดีย่อมสุขใจในโลกหน้า คนทำดีย่อมสุขใจในโลก ทั้งสองโลก เมื่อคิดว่าตนได้ทำแต่บุยกุศล ย่อมสุขใจ ตายไปเกิดในสุคติ ยิ่งสุขใจยิ่งขึ้น",
  "19": "คนที่ท่องจำตำราได้มาก แต่มัวประมาทเสีย ไม่ทำตามคำสอน ย่อมไม่ได้รับผลที่พึงได้จากการบวช เหมือนเด็กเลี้ยงโค นับโคให้คนอื่นเขา",
  "20": "ถึงจะท่องจำตำราได้น้อย แต่ประพฤติชอบธรรม ละราคะ โทสะ และโมหะได้ รู้แจ้งเห็นจริง มีจิตหลุดพ้น ไม่ยึดมั่น ถือมั่น ทั้งปัจจุบันและอนาคต เขาย่อมได้รับผลที่พึงได้จากการบวช",
  "chap2": "ไม่ประมาท",
  "21": "ความไม่ประมาท เป็นทางอมตะ ความประมาท เป็นทางแห่งความตาย ผู้ไม่ประมาท ไม่มีวันตาย ผู้ประมาท ถึงมีชีวิตอยู่ก็เหมือนคนตายแล้ว",
  "22": "บัณฑิตรู้ข้อแตกต่าง ระหว่างความประมาทกับความไม่ประมาท จึงยินดีในความไม่ประมาท อันเป็นแนวทางของพระอริยะ",
  "23": "ท่านผู้ฉลาดเหล่านั้น หมั่นเจริญกรรมฐาน มีความเพียรมั่นอยู่เป็นนิจศีล บรรลุพระนิพพานอันเป็นสภาวะที่สูงส่ง อิสระจากกิเลสเครื่องผูกมัด",
  "24": "ยศย่อมเจริญแก่ผู้ขยัน มีสติ มีการงานสะอาด ทำงานด้วยความรอบคอบระมัดระวัง เป็นอยู่โดยชอบธรรม ไม่ประมาท",
  "25": "ด้วยความขยัน ด้วยความไม่ประมาท ด้วยความสำรวมระวัง และด้วยการข่มใจตนเอง ผู้มีปัญญาควรสร้างเกาะ (ที่พึ่ง) แก่ตนเอง ที่ห้วงน้ำ (กิเลส) ไม่สามารถท่วมได้",
  "26": "คนพาล ทรามปัญญา มักมัวประมาทเสีย ส่วนคนฉลาด ย่อมรักษาความไม่ประมาท เหมือนรักษาทรัพย์อันประเสริฐ",
  "27": "พวกเธออย่ามัวประมาท อย่ามัวเอาแต่สนุกยินดีในกามคุณอยู่เลย ผู้ไม่ประมาท เพ่งพินิจตามความเป็นจริงเท่านั้น จึงจะบรรลุถึงความสุขอันไพบูลย์ได้",
  "28": "เมื่อใดบัณฑิตกำจัดความประมาทด้วยความไม่ประมาท เมื่อนั้นเขานับว่าได้ขึ้นสู่ 'ปราสาทคือปัญญา' ไร้ความเศร้าโศก สามารถมองเห็นประชาชน ผู้โง่เขลา ผู้ยังต้องเศร้าโศกอยู่ เหมือนคนยืนบนยอดภูเขา มองลงมาเห็นฝูงชนที่ยืนอยู่บนพื้นดิน ฉะนั้น",
  "29": "ผู้มีปัญญามักไม่ประมาท เมื่อคนอื่นพากันประมาท และตื่น เมื่อคนอื่นหลับอยู่ เขาจึงละทิ้งคนเหล่านั้นไปไกล เหมือนม้าฝีเท้าเร็ว วิ่งเลยม้าแกลบ ฉะนั้น",
  "30": "ท้าวมฆวานได้เป็นใหญ่กว่าทวยเทพ เพราะผลของความไม่ประมาท บัณฑิตจึงสรรเสริญความไม่ประมาท และติเตียนความประมาททุกเมื่อ",
  "31": "ภิกษุผู้ยินดีในตัวความไม่ประมาท เห็นภัยในความประมาท ย่อมเผากิเลสเครื่องผูกมัดได้ เหมือนไฟเผาเชื้อทุกชนิด",
  "32": "ภิกษุผู้ไม่ประมาท เห็นภัยในความประมาท ไม่ม่ทางเสื่อม ย่อมอยู่ใกล้นิพพานเป็นแน่แท้",
  "chap3": "จิต",
  "33": "จิตดิ้นรน กลับกลอก ป้องกันยาก ห้ามยาก คนมีปัญญาสามารถดีดให้ตรงได้ เหมือนช่างศรดัดลูกศร",
  "34": "มัสยาถูกเขาจับโยนไปบนบก ย่อมดิ้นรน เพื่อจะกลับไปยังแหล่งน้ำที่เคยอาศัย จิตใจเราก็เช่นเดียวกัน ดิ้นรนไปหากามคุณ เพราะฉะนั้น จึงควรละเว้นกามคุณเสีย",
  "35": "จิตควบคุมยาก เปลี่ยนแปลงเร็ว ใฝ่ในอารมณ์ตามที่ใคร่ ฝึกจิตเช่นนั้นได้เป็นการดี เพราะจิตที่ฝึกดีแล้ว นำความสุขมาให้",
  "36": "จิตเห็นได้ยาก ละเอียดยิ่งนัก มักใฝ่ในอารมณ์ตามที่ใคร่ ผู้มีปัญญาจึงควรควบคุมจิตไว้ให้ดี เพราะจิตที่ควบคุมได้แล้ว นำสุขมาให้",
  "37": "จิตท่องเที่ยวไปไกล เที่ยวไปดวงเดียว ไม่มีรูปร่าง อาศัยอยู่ในร่างกายนี้ ใครควบคุมจิตนี้ได้ ย่อมพ้นจากบ่วงมาร",
  "38": "ปัญญาย่อมไม่บริบูรณ์ แก่ผู้มีจิตไม่มั่นคง ไม่รู้พระสัทธรรม มีความเลื่อมใสไม่จริงจัง",
  "39": "ผู้มีสติตื่นตัวอยู่เนืองนิตย์ มีจิตเป็นอิสระจากราคะและโทสะ ละบุญและบาปได้ ย่อมไม่กลัวอะไร",
  "40": "เมื่อรู้ว่าร่างกายนี้แตกดับง่ายเหมือนหม้อน้ำ พึงป้องกันจิตให้มั่นเหมือนป้องกันเมืองหลวง แล้วพึงรบ กับ พญามารด้วยอาวุธคือปัญญา เมื่อรบชนะแล้วพึงรักษาชัยชนะนั้นไว้ ระวังอย่าตกอยู่ในอำนาจมารอีก",
  "41": "อีกไม่นาน ร่างกายนี้ จักปราศจากวิญญาณ ถูกทอดทิ้ง ทับถมแผ่นดิน เหมือนท่อนไม้อันหาประโยชน์มิได้",
  "42": "จิตที่ฝึกฝนผิดทาง ย่อมทำความเสียหายได้ ยิ่งกว่าศัตรูทำต่อศัตรู หรือคนจองเวรทำต่อคนจองเวร",
  "43": "มารดาก็ทำให้ไม่ได้ บิดาก็ให้ไม่ได้ ญาติพี่น้องก็ทำให้ไม่ได้ แต่จิตที่ฝึกฝนไว้ชอบย่อมทำสิ่งนั้นให้ได้ และทำให้ได้อย่างประเสริฐด้วย",
  "chap4": "ดอกไม้",
  "44": "ใครจักครองแผ่นดินนี้ พร้อมทั้งยมโลก และเทวโลก ใครจักเลือกเฟ้นพระธรรมบท ที่ทรงแสดงไว้ดีแล้ว เหมือนนายมาลาการผู้ฉลาด เลือกเก็บดอกไม้",
  "45": "พระเสขะจักครองแผ่นดินนี้ พร้อมทั้งยมโลกและเทวโลก พระเสขะจักเลือกเฟ้นพระธรรมบท ที่ทรงแสดงไว้ดีแล้ว เหมือนนายมาลาการผู้ฉลาด เลือกเก็บดอกไม้",
  "46": "เมี่อรู้ว่าร่างกายนี้แตกสลายง่าย และว่างเปล่า เช่นเดียวกับฟองน้ำ และพยับแดด ก็ควรทำลายบุษปศรของกามเทพ ไปให้พ้นทัศนวิสัยของมัจจุราชเสีย",
  "47": "มฤตยูฉุดคร่าคนผู้มัวเก็บดอกไม้ (กามคุณ) มีใจเกี่ยวข้องอยู่ในกามคุณไป เหมือนห้วงน้ำใหญ่หลากมา พัดพาเอาชาวบ้านผู้หลับไหลไป",
  "48": "ผู้ที่มัวเก็บดอกไม้ (กามคุณ) เพลินอยู่ มีจิตใจข้องอยู่แต่ในกามคุณไม่รู้จักอิ่ม มักตกอยู่ในอำนาจมฤตยู",
  "49": "มุนีพึงจาริกไปในเขตคาม ไม่ทำลายศรัทธาและโภตะของชาวบ้าน ดุจภมรดูดรสหวานของบุปผชาติแล้วจากไป ไม่ให้สีและกลิ่นชอกช้ำ",
  "50": "ไม่ควรแส่หาความผิดผู้อื่น หรือธุระที่เขาทำแล้วหรือยังไม่ทำ ควรตรวจดูเฉพาะกิจ ที่ตนทำหรือยังไม่ทำเท่านั้น",
  "51": "วาจาสุภาสิต ของผู้ทำไม่ได้ตามพูด ย่อมไม่มีประโยขน์อะไร ดุจดอกไม้สีสวย แต่ไร้กลิ่น",
  "52": "วาจาสุภาษิต ของผู้ทำได้ตามพูด ย่อมอำนวยผลดี ดุจดอกไม้สีสวยและมีกลิ่นหอม",
  "53": "เมื่อเกิดมาแล้วจะต้องตาย ก็ควรสร้างบุญกุศลไว้ให้มาก เหมือนนายมาลาการร้อยพวงมาลัย เป็นจำนวนมากจากกองดอกไม้",
  "54": "กลิ่นปุปผชาติ ก็หอมทวนลมไม่ได้ กลิ่นจันทน์ กฤษณา หรือดอกมะลิ ก็หอมทวนลมไม่ได้ แต่กลิ่นสัตบุรุษ หอมทวนลมไม่ได้ สัตบุรุษ ย่อมหอมฟุ้งขจรไปทั่วทุกทิศ",
  "55": "กลิ่นศีล หอมยิ่งกว่า ของหอมเหล่านี้ คือ จันทน์ กฤษณา ดอกอุบล และ กะลำพัก",
  "56": "กฤษณา หรือจันทน์ มีกลิ่นหอมน้อยนัก แต่กลิ่นหอมของท่านผู้ทรงศีลประเสริฐนัก หอมฟุ้งกระทั่งถึงทวยเทพยดา",
  "57": "มารย่อมค้นไม่พบวิถีทาง ของผู้ทรงศีลผู้อยู่ด้วยความไม่ประมาท ผู้หลุดพ้นจากอาสวกิเลส เพราะรู้ชอบ",
  "58": "ดอกบัว มีกลิ่นหอม รื่นรมย์ใจ เกิดบนสิ่งปฏิกูล ที่เขาทิ้งไว้ใกล้ทางใหญ่ ฉันใด",
  "59": "ท่ามกลางหมู่ปุถุชน ผู้โง่เขลา ผู้เป็นเสมือนสิ่งปฏิกูล พระสาวกของพระสัมมาสัมพุทธเจ้า ย่อมรุ่งเรืองด้วยปัญญา ฉันนั้น",
  "chap5": "คนพาล",
  "60": "ราตรีนาน สำหรับคนนอนไม่หลับ ระยะทางโยชน์หนึ่งไกล สำหรับผู้ล้าแล้ว สังสารวัฎยาวนาน สำหรับคนพาล ผู้ไม่รู้แจ้งพระสัทธรรม",
  "61": "หากแสวงหาไม่พบเพื่อนที่ดีกว่าตน หรือเพื่อนที่เสมอกับตน ก็พึงเที่ยวไปคนเดียว เพราะมิตรภาพ ไม่มีในหมู่คนพาล",
  "62": "คนโง่มัวคิดวุ่นวายว่า เรามีบุตร เรามีทรัพย์ เมื่อตัวเขาเองก็ไม่ใช่ของเขา บุตรและทรัพย์จะเป็นของเขาได้อย่างไร",
  "63": "คนโง่ รู้ตัวว่าโง่ ยังมีทางเป็นบัณฑิตได้บ้าง แต่โง่แล้ว อวดฉลาด นั่นแหละเรียกว่าคนโง่แท้",
  "64": "ถึงจะอยู่ใกล้บัณฑิต เป็นเวลานานชั่วชีวิต คนโง่ก็หารู้พระธรรมไม่ เหมือนจวักไม่รู้รสแกง",
  "65": "ปัญญาชน คบบัณฑิต แม้เพียงครู่เดียว ก็พลันรู้แจ้งพระธรรม เหมือนลิ้นรู้รสแกง",
  "66": "เหล่าคนพาล ปัญญาทราม ทำตัวเองให้เป็นศัตรูของตัวเอง เที่ยวก่อแต่บาปกรรมที่มีผลเผ็ดร้อน",
  "67": "กรรมใดทำแล้วทำให้เดือดร้อนภายหลัง อีกทั้งทำให้ร้องไห้น้ำตานอง รับสนองผลของการกระทำ กรรมนั้นไม่ดี",
  "68": "กรรมใดทำแล้ว ไม่เดือดร้อนภายหลัง ทั้งผู้กระทำก็เบิกบานสำราญใจ ได้เสวยผลของการกระทำ กรรมนั้นดี",
  "69": "ตลอดระยะเวลาที่บาปยังไม่ให้ผล คนพาลสำคัญบาปหวานปานน้ำผึ้ง เมื่อใดบาปให้ผล เมื่อนั้นเขาย่อมได้รับทุกข์",
  "70": "คนพาล ถึงจะบำเพ็ญตบะ โดยเอาปลายหญ้าคาจิ้มอาหารกิน ทุกเดืน การปฏิบัติของเขาไม่เท่าหนึ่งในสิบหกส่วน ของการปฏิบัติของท่านผู้บรรลุธรรม",
  "71": "กรรมชั่วที่ทำแล้ว ยังไม่ให้ผลทันทีทันใด เหมือนนมรีดใหม่ๆ ไม่กลายเป็นนมเปรี้ยวในทันที แต่มันจะค่อยๆ เผาผลาญผู้กระทำในภายหลัง หมือนไฟไหม้แกลบ",
  "72": "คนพาลได้ความรู้มา เพื่อการทำลายถ่ายเดียว ความรู้นั้น ทำลายคุณความดีเขาสิ้น ทำให้มันสมองของเขาตกต่ำไป",
  "73": "ภิกษุพาล ปรารถนาชื่อเสียงเกียรติยศที่ไม่เหมาะ อยากเป็นใหญ่กว่าพระภิกษุทั้งหมด อยากเป็นเจ้าอาวาส อยากได้รับบูชาสักการะจากชาวบ้านทั้งหลาย",
  "74": "'ขอให้คฤหัสถ์ และบรรพชิต จงสำคัญว่า เราเท่านั้นทำกิจนี้ ขอให้เขาเหล่านั้นอยู่ในบังคับบัญชาของเรา ไม่ว่ากิจการใหญ่หรือเล็ก' ภิกษุพาล มักจะคิดใฝ่ฝันเช่นนี้ ความทะเยอทะยาน และความหยิ่งก็พลอยเพิ่มขึ้น",
  "75": "ทางหนึ่งแสวงหาลาภ ทางหนึ่งไปนิพพาน รู้อย่างนี้แล้ว ภิกษุพุทธสาวก ไม่ควรไยดีลาภสักการะ ควรอยู่อย่างสงบ",
  "chap6": "บัณฑิต",
  "76": "ถ้าพบนักปราชญ์ ที่คอยว่ากล่าวตักเตือนชี้ข้อบกพร่อง เสมือนผู้บอกขุมทรัพย์ให้ ควรคบหาบัณฑิตเช่นนั้น เพราะเมื่อคบหาคนเช่นนั้น จะมีแต่ความเจริญไม่มีความเสื่อม",
  "77": "จงยอมตนให้บัณฑิตตักเตือนพร่ำสอน และกีดกันจากความชั่ว คนที่คอยสั่งสอนเช่นนี้ คนดีรัก แต่คนชั่วเกลียด",
  "78": "ไม่พึงคบมิตรชั่ว ไม่พึงคบคนเลวทราม พึงคบกัลยาณมิตร พึงคบคนที่ดีเยี่ยม",
  "79": "ผู้ดื่มรสพระธรรม มีใจสงบ ย่อมอยู่เป็นสุข บัณฑิตย่อมยินดีในธรรม ที่พระอริยเจ้าแสดงไว้เสมอ",
  "80": "ชาวนาไขน้ำเข้านา ช่างศรดัดลูกศร ช่างไม้ถากไม้ บัณฑิตฝึกตนเอง",
  "81": "ขุนเขาไม่สะเทือนเพราะแรงลมฉันใด บัณฑิตก็ไม่หวั่นไหวเพราะนินทาหรือสรรเสริญฉันนั้น",
  "82": "ห้วงน้ำลึก ใสสะอาดสงบฉันใด บัณฑิตฟังธรรมแล้วย่อมมีจิตใจสงบฉันนั้น",
  "83": "สัตบุรุษ ยอมเสียสละได้ทุกสิ่งทุกอย่าง ไม่มัวพร่ำเพ้อ แต่เรื่องกามคุณ ไม่ว่าได้รับสุขหรือทุกข์ บัณฑิตไม่แสดงอาการยินดียินร้าย (เกินกว่าเหตุ)",
  "84": "ไม่ควรทำชั่วเพราะเห็นแก่ตัว หรือคนอื่น ไม่ควรปรารถนาบุตร ทรัพย์ รัฐ หรือความสำเร็จ แก่ตนโดยทางที่ไม่ชอบธรรม ควรมีศีล มีปัญญา มั่นอยู่ในธรรม",
  "85": "ในหมู่มนุษย์ทั้งหลาย น้อยคนนักจักข้ามฝั่งไปได้ ส่วนคนนอกนี้ ก็ได้แต่วิ่งเลียบเลาะริมฝั่ง",
  "86": "ผู้ประพฤติตามคำสั่งสอนที่ตรัสดีแล้ว ย่อมข้ามอาณาจักรพญามาร ที่ข้ามได้แสนยาก ไปถึงอีกฝั่งหนึ่ง (คือพระนิพพาน)",
  "87": "บัณฑิตพึงละธรรมดำ (บาป) สร้างสมธรรมขาว (บุญ) เมื่อละบ้านเรือนมาถือเพศบรรพชิตแล้ว ก็ควรยินดีในความสงัดวิเวก ซึ่งยากที่คนธรรมดาจะยินดีได้",
  "88": "บัณฑิตพึงละกามคุณ สลัดอาลัยหมดสิ้น ทำตนให้บริสุทธิ์ ปราศจากเครื่องเศร้าหมองแห่งจิต",
  "89": "ท่านที่อบรมจิตใจเป็นอย่างดี ในคุณธรรมที่จะนำไปสู่การตรัสรู้ ไม่ยึดมั่น ยินดีในความปล่อยวาง ท่านเหล่านั้น เป็นพระอรหันต์ สงบ สว่าง เข้าถึงพระนิพพานแล้วในโลกนี้",
  "chap7": "พระอรหันต์",
  "90": "ผู้เดินทางถึงจุดหมายปลายทางแล้ว วิมุติหลุดพ้นโดยประการทั้งปวง หมดโศก หมดเครื่องพัวพันแล้ว ความร้อนใจก็หมดไป",
  "91": "ผู้มีสติย่อมขยันขันแข็ง ไม่ยึดติดแหล่งที่อาศัย ละทิ้งไปตามลำดับ เหมือนกับพญาหงส์ทิ้งสระน้ำ",
  "92": "ท่านที่หมดการสะสม (ปัจจัยหรือกรรมดีกรรมชั่ว) พิจารณาโภชนะก่อนบริโภค เข้าถึงความหลุดพ้น อันว่างจากกิเลสและไร้นิมิตหมายคือกิเลส บุคคลเช่นนี้ ยากที่สามัญชนขะตามทัน เหมือนนกบินบนท้องฟ้า ตามทันยาก",
  "93": "ผู้หมดกิเลส ไม่เห็นแก่กิน เข้าถึงความหลุดพ้น อันว่างจากกิเลสและไร้นิมิตหมายคือกิเลส บุคคลเช่นนี้มิได้ทิ้งร่องรอยอะไรไว้เลย เหมือนนกบินบนท้องฟ้า หารอยอันใดมิได้",
  "94": "ท่านผู้ใดควบคุมอินทรีย์คือ ตา, หู, จมูก, ลิ้น, กาย, ใจ ได้ เหมือนม้าที่สารถีควบคุมได้อย่างดี ท่านผู้นี้หมดความไว้ตัว หมดกิเลส มั่นคง ย่อมเป็นที่โปรดปราน แม้กระทั่งของเทวดาทั้งหลาย",
  "95": "พระอรหันตฺเปรียบได้กับแผ่นดิน ไม่เคยโกรธขึ้งใคร มีจิตคงที่ เหมือนหลักเมือง มีจรรยาสะอาด เหมือนสระน้ำที่ใสไร้เปลือกตม ผู้มีคุณสมบัติเห็นปานนี้ ย่อมไม่เวียนว่ายตายเกิดอีก",
  "96": "พระอรหันตฺผู้เป็นอิสระเพราะรู้แจ้ง ผู้สงบระงับ และมีจิตมั่นคง ใจของท่าน ย่อมสงบ วาจาก็สงบ การกระทำทางกายก็สงบ",
  "97": "ผู้ไม่เชื่อใครง่ายตนกว่าจะพิสูจน์ด้วยตนเอง ๑ ผู้รู้แจ้งพระนิพพาน ๑ ผู้หมดการเวียนว่ายตายเกิด ๑ ผู้หมดโอกาสที่จะทำดีหรือชั่ว ๑ ผู้หมดกิเลสที่ทำให้หวัง ๑ ห้าประเภทนี้แล เรียกว่า 'ยอดคน'",
  "98": "ไม่ว่าจะเป็นบ้าน หรือป่า ไม่ว่าจะเป็นที่ลุ่ม หรือที่ดอน พระอรหันต์ทั้งหลายอยู่ในที่ใด ที่นั้น เป็นที่น่ารื่นรมย์",
  "99": "ป่าที่คนทั่วไปไม่ชื่นชม เป็นรมณียสถาน สำหรับท่านผู้มหมดราคะ เพราะพระท่านมิได้ใฝ่กามคุณ",
  "chap8": "พัน",
  "100": "คำพูดที่เหลวไหลไร้ประโยชน์ตั้งพันคำ ก็สู้คำพูดที่มีประโยชน์คำเดียวไม่ได้ เพราะฟังแล้วทำให้จิตใจสงบ",
  "101": "บทกวีตั้งพันโศลก แต่ไร้ประโยชน์ ไม่เท่าบทกวีบรรทัดเดียว ที่ทำให้ผู้ฟังได้รับความสงบ",
  "102": "บทกวีบรรยายธรรมบทเดียว ที่ทำให้ผู้ฟังได้รับความสงบ ประเสริฐกว่าบทกวีที่ท่องจำได้ตั้งร้อยโศลก แต่ไม่มีประโยชน์แม้แต่บทเดียว",
  "103": "ถึงจะรบชนะข้าศึกเป็นพันๆ ราย ก็ไม่นับเป็นยอดขุนพล แต่ผู้ที่เอาชนะจิตใจตน จึงเรียก 'ยอดขุนพล' แท้จริง",
  "104": "เอาชนะตนได้นั้นแล ประเสริฐ",
  "105": "ผู้ที่ฝึกตนได้ ระวังระไวตลอดเวลา ถึงเทวดา คนธรรพ์ และพระพรหม ก็เอาชนะไม่ได้",
  "106": "การบูชาท่านผู้ฝึกตน แม้เพียงหนึ่งครั้ง บังเกิดผลมหาศาล ยิ่งกว่าสละทรัพย์บูชายัญเดือนละพัน เป็นเวลาติดต่อกันถึงร้อยปี",
  "107": "การบูชาท่านผู้ฝึกตนแม้เพียงครู่เดียว บังเกิดผลมหาศาล ยิ่งกว่าการบูชาไฟในป่า เป็นเวลาตั้งร้อยปี",
  "108": "ไม่ว่ายัญชนิดไหน ที่ผู้ใคร่บุญพึงบูชาตลอดปี การบูชายัญนั้นมีค่าไม่เท่าหนึ่งในส่ของการยกมือไหว้ ท่านผู้ปฏิบัติตรงตามอริยมาาคแม้เพียงครั้งเดียว การไหว้บุคคลเช่นนั้นประเสริฐกว่าเป็นไหนๆ",
  "109": "ผู้กราบไหว้ อ่อนน้อมถ่อมตัว ต่อผู้ใหญ่เป็นนิจศีล ย่อมเจริญด้วยคุณธรรมสี่ประการคือ อายุ ชื่อเสียง สุข และกำลัง",
  "110": "ผู้มีศีล มีสมาธิ ประเสริฐกว่าชีวิตตั้งร้อยปี ของคนทุศีล ไร้สมาธิ",
  "111": "ผู้มีปัญญา มีสมาธิ มีชีวิตอยู่วันเดียว ประเสริฐกว่าชีวิตตั้งร้อยปี ของผู้ทรามปัญญา ไร้สมาธิ",
  "112": "ผู้มีความเพียรมั่นคง มีชีวิตอยู่วันเดียว ประเสริฐกว่าชีวิตตั้งร้อยปี ของผู้เกียจคร้าน ไร้ความเพียร",
  "113": "ผู้พิจารณาเห็นความเกิด-ดับแห่งสังขาร มีชีวิตอยู่วันเดียว ประเสริฐกว่าชีวิตตั้งร้อยปี ของผู้ไม่พิจารณาเห็น",
  "114": "ผู้พบทางอมตะ มีชีวิตอยู่วันเดียว ประเสริฐกว่าชีวิตตั้งร้อยปี ของผู้ไม่พบ",
  "115": "ผู้เห็นพระธรรมอันประเสริฐ มีชีวิตอยู่วันเดียว ประเสริฐกว่าชีวิตตั้งร้อยปี ของผู้ไม่เห็น",
  "chap9": "บาป",
  "116": "พึงรีบเร่งกระทำความดี และป้องกันจิตจากความชั่ว เพราะเมื่อกระทำความดีช้าไป ใจจะกลับยินดีในความชั่ว",
  "117": "ถ้าหากจำต้องทำชั่วไซร้ ก็ไม่ควรทำบ่อยนัก และไม่ควรพอใจในการทำชั่วนั้น เพราะการสะสมบาป นำทุกข์มาให้",
  "118": "ถ้าหากจะทำความดี ก็ควรทำดีบ่อยๆ ควรพอใจในการทำความดีนั้น เพราะการสะสมความดีนำสุขมาให้",
  "119": "เมื่อบาปยังไม่ส่งผล คนชั่วก็เห็นว่าเป็นของดี ต่อเมื่อมันเผล็ดผลเมื่อใด เมื่อนั้นแหละเขาจึงรู้พิษสงของบาป",
  "120": "เมื่อความดียังไม่ส่งผล คนดีก็มองเห็นความดีเป็นความชั่ว ต่อเมื่อใดความดีเผล็ดผล เมื่อนั้นแหละเขาจึงจะเห็นผลของความดี",
  "121": "อย่าดูถูกความชั่วเล็กน้อยว่าจักไม่สนองผล น้ำตกจากเวหาทีละหยาดๆ ยังเต็มตุ่มได้ คนพาลทำความชั่วทีละเล็กละน้อย ย่อมเต็มด้วยความชั่วได้เช่นกัน",
  "122": "อย่าดูถูกบุญเล็กน้อยว่าจักไม่สนองผล น้ำตกจากเวหาทีละหยาดๆ ยังเต็มตุ่มได้ นักปราชญ์สะสมบุญทีละเล็กละน้อย ย่อมเต็มด้วยบุญได้เช่นกัน",
  "123": "พ่อค้ามีทรัพย์มาก มีพวกน้อย ละเว้นทางที่มีภัย คนรักชีวิตละเว้นยาพิษ ฉันใด บุคคลพึงละบาป ฉันนั้น",
  "124": "เมื่อมือไม่มีแผล บุคคลย่อมจับต้องยาพิษได้ ยาพิษนั้นไม่สามารถทำอันตรายได้ บาปก็ไม่มีแก่ผู้ไม่ทำบาป",
  "125": "บาปก็ย่อมตามสนองผู้โง่เขลา ซึ่งทำร้ายบุคคลที่ไม่ทำร้ายตอบ ผู้หมดจด ปราศจากกิเลส ดุจธุลีที่ซัดทวนลม (วกกลับมาหาผู้ซัด)",
  "126": "สัตว์บางพวกกลับมาเกิดอีก พวกที่ทำบาป ไปนรก พวกที่ทำดี ไปสวรรค์ พวกที่หมดอาสวกิเลส ปรินิพพาน",
  "127": "ไม่ว่าบนท้องฟ้า ไม่ว่าท่ามกลางสมุทร ไม่ว่าในหุบเขา ไม่มีแม้แต่แห่งเดียว ที่ผู้ทำกรรมชั่วอาศัยอยู่ จะหนีพ้นกรรมไปได้",
  "128": "ไม่ว่าบนท้องฟ้า ไม่ว่าท่ามกลางสมุทร ไม่ว่าในหุบเขา ไม่มีแม้สักแห่งเดียว ที่คนเราอาศัยอยู่แล้ว จะหนีพ้นความตายได้",
  "chap10": "ลงทัณฑ์",
  "129": "สัตว์ทั้งหมดกลัวโทษทัณฑ์ สัตว์ทั้งหมดกลัวความตาย เปรียบตนเองกับผู้อื่นอย่างนี้แล้ว ไม่ควรฆ่าเอง ไม่ควรสั่งให้คนอื่นฆ่า",
  "130": "สัตว์ทั้งหมดกลัวโทษทัณฑ์ สัตว์ทั้งหมดรักชีวิตของตน เปรียบตนเองกับคนอื่นอย่างนี้แล้ว ไม่ควรฆ่าเอง ไม่ควรสั่งให้คนอื่นฆ่า",
  "131": "สัตว์ทั้งหลายล้วนต้องการความสุข ผู้ที่ต้องการความสุขแก่ตน แต่เบียดเบียนสัตว์อื่น ตายไปแล้วย่อมไม่ได้รับความสุข",
  "132": "สัตว์ทั้งหลายล้วนต้องการความสุข ผู้ที่ต้องความสุขแก่ตน ไม่เบียดเบียนสัตว์อื่น ตายไปแล้วย่อมได้รับความสุข",
  "133": "อย่ากล่าวคำหยาบแก่ใครๆ เมื่อถูกท่านด่าว่า เขาจะโต้ตอบท่าน การพูดจากร้าวร้าวกันเป็นเหตุก่อทุกข์ อาจลุกลามถึงขั้นลงมือประทุษร้ายกัน",
  "134": "ถ้าเธอทำตนให้เงียบเสียงได้ เหมือนฆ้องแตก ก็นับว่าเธอเข้าถึงนิพพานแล้ว เธอก็จะไม่ต้องทะเลาะเบาะแว้งกับใครอีก",
  "135": "ความแก่และความตาย ไล่ต้อนอายุสัตว์ทั้งหลายไป เหมือนเด็กเลี้ยงโค ถือท่อนไม้ คอยไล่ต้อนฝูงโคไปสู่ที่หากิน",
  "136": "คนพาล เวลาทำชั่ว หาสำนึกถึงผลของมันไม่ คนทรามปัญญามีกเดือดร้อน เพราะกรรมชั่วของตัว เหมือนถูกไฟไหม้",
  "137": "ผู้ทำร้ายลงทัณฑ์แก่บุคคล ผู้ไม่เบียดเบียน ไม่ทำร้ายใคร ย่อมได้รับผลสนองสิบอย่าง อย่างใดอย่างหนึ่งทันตาเห็น",
  "138": "ได้รับเวทนาอย่างรุนแรง ได้รับความเสื่อมเสีย ถูกทำร้ายร่างกาย เจ็บป่วยอย่างหนัก กลายเป็นคนวิกลจริต",
  "139": "ต้องราชภัย ถูกกล่าวหาอย่างรุนแรง ไร้ญาติพี่น้อง ทรัพย์สมบัติก็พินาศฉิบหาย",
  "140": "หรือไม่บ้านเรือนของเขย่อมถูกไฟไหม้ ตายไป เขาผู้ทรามก็ตกนรก",
  "141": "ไม่ใช่ประพฤติตนเป็นชีเปลือย ไม่ใช่มุ่นชฏา ไม่ใช่เอาโคลนทาร่างกาย ไม่ใช่การอดอาหาร ไม่ใช่นอนบนดิน ไม่ใช่คลุกฝุ่นธุลี ไม่ใช่นั่งกระโหย่ง ที่ทำให้คนผู้ยังไม่ข้ามพ้นความสงสัย บริสุทธิ์",
  "142": "ถึงจะแต่งกายแบบใดๆ ก็ตาม ถ้าใจสงบระงับ ควบคุมตัวได้ มั่นคง บริสุทธิ์ ไม่เบียดเบีนคนอื่น เรียกว่า พราหมณ์ สมณะ หรือ ภิกษุ",
  "143": "ผู้หักห้ามใจไม่ทำชั่วเพราะละอายบาป หาได้น้อยนักในโลกนี้ คนเช่นนี้ย่อมปลุกตัวเองจากหลับอยู่เสมอ เหมือนม้าดี ระวังตัวเองให้พ้นแส้",
  "144": "ธรรมดาม้าดี เมื่อถูกลงแส้ครั้งหนึ่ง ย่อมสำนึก (ความผิดครั้งแรก) และพยายาม (วิ่งให้เร็ว) พวกเธอก็จงทำตนเช่นนั้น อาศัยศรัทธา, ศีล, ความเพียรสมาธิ, การวินิจฉัยธรรม, ความสมบูรณ์ด้วย ความรู้และความประพฤติ, และอาศัยสติ พวกเธอจักละทุกข์ได้ไม่น้อยเลย",
  "145": "ชาวนา ไขน้ำเข้านา ช่าวศร ดัดลูกศร ช่างไม้ ถากไม้ คนดี ฝึกตนเอง",
  "chap11": "ชรา",
  "146": "จะมัวร่าเริง สนุกสนานกันทำไม ในเมื่อโลกกำลังลุกเป็นไฟอยู่เนืองนิตย์ พวกเธอถูกความมืดมิดปิดบังตา ไยไม่แสวงหาแสงสว่างกันเล่า",
  "147": "จงดูร่างกายที่ว่าสวยงามนี้เถิด เต็มไปด้วยแผล สร้างขึ้นด้วยกระดูก มากด้วยโรค มากด้วยความครุ่นคิดปรารถนา หาความยั่งยืนถาวรมิได้",
  "148": "ร่างกายนี้แก่หง่อมแล้ว เป็นที่อาศัยของโรค แตกทำลายง่าย ร่างกายอันเน่าเหม็นนี้ จักแตกสลายพังภินท์ เพราะชีวิตสิ้นสุดลงที่ความตาย",
  "149": "กระดูกเหล่านี้ มีสีขาวเหมือนสีนกพิราบ ไม่เป็นที่ต้องการของใครๆ ดุจน้ำเต้าในฤดูสารท ดูแล้วไม่น่าปรารถนายินดี",
  "150": "ร่างกายนี้เป็น 'อัฐินคร' (เมืองกระดูก) ฉาบด้วยเนื้อและโลหิต เป็นที่สถิตแห่ง ชรา มรณะ ความเย่อหยิ่ง และความดูถูกบุญคุณกัน",
  "151": "ราชรถ อันวิจิตรงดงาม ยังเก่าได้ แม้ร่างกายของเรา ก็ไม่พ้นชราภาพ แต่ธรรมของสัตบุรุษหาแก่ไม่ สัตบุรุษทั้งหลาย ย่อมกล่าวสอนกันเช่นนี้แล",
  "152": "คนโง่แก่เปล่า เหมือนโคถึก มากแต่เนื้อหนังมังสา แต่ปัญญาหาเพิ่มขึ้นไม่",
  "153": "เมื่อไม่พบนายช่างผู้สร้างเรือน เราได้เวียนว่ายตายเกิด ในสงสารนับชาติไม่ถ้วน การเกิดแล้วเกิดอีกเป็นทุกข์",
  "154": "นายช่างเอย บัดนี้เราพบท่านแล้ว ท่านจะสร้างเรือนไม่ได้อีก จันทัน อกไก่ เราทำลายหมดแล้ว จิตของเราบรรลุนิพพาน หมดความทะยานอยากแล้ว",
  "155": "เมื่อยังอยู่ในวัยหนุ่มสาว ไม่ทำตัวให้ดีและไม่หาทรัพย์ไว้ พอถึงวัยแก่เฒ่า พวกเขาย่อมนั่งซบเซา เหมือนนกกะเรียนแก่ จับเจ่าอยู่ริมสระที่ไร้ปลา",
  "156": "เมื่ออยู่ในวัยหนุ่มสาว ไม่ทำตัวให้ดี และไม่หาทรัพย์ไว้ พอถึงวัยแก่เฒ่า พวกเขาย่อมนอนทุกข์ ทอดถอนใจรำพึงถึงความหลัง เหมือนธนูหัก (ใช้ยิงอะไรก็ไม่ได้)",
  "chap12": "ตน",
  "157": "ถ้ารู้ว่าตนเป็นที่รัก พึงรักษาตนไว้ให้ดี บัณฑิตควรประคับประคองตนไว้ ไม่ทั้งสามวัยใดวัยหนึ่ง",
  "158": "ควรปฏิบัติตนให้ดีก่อน แล้วค่อยสอนคนอื่น บัณฑิตเมื่อทำได้อย่างนี้ จึงจะไม่สร้างมลทินแก่ตน",
  "159": "สอนคนอื่นอย่างใด ควรทำตนอย่างนั้น ฝึกตนเองแล้วค่อยฝึกคนอื่น เพราะตัวเราเองฝึกยากยิ่งนัก",
  "160": "เราต้องพึ่งตัวเราเอง คนอื่นใครเล่าจะเป็นที่พึ่งได้ บุคคลผู้ฝึกตนดีแล้ว ย่อมได้ที่พึ่งที่ได้แสนยาก",
  "161": "บาปที่ตนทำเอง เกิดในตนเอง และตนเองเป็นผู้สร้างไว้ ย่อมทำลายคนโง่ให้ย่อยยับ เหมือนเพชร ทำลายแก้วมณี",
  "162": "คนทุศีล ก็เหมือนกับต้นไม้ ที่เถาวัลย์ขึ้นจนรก เขาทำตัวให้วอดวายเอง มิจำต้องรอให้ศัตรูมาคอยกระทำให้",
  "163": "กรรมไม่ดี ทั้งไม่มีประโยชน์แก่ตน ทำง่าย แต่กรรมดีและมีประโยชน์ ทำได้ยากยิ่ง",
  "164": "คนทรามปัญญา มีความเห็นผิด ติเตียนคำสอน ของเหล่าพระอริยะผู้อรหันต์ ผู้มีชีวิตอยู่โดยธรรม เขาย่อมเกิดมาเพื่อฆ่าตัวเขาเอง เหมือนขุยไผ่ฆ่าต้นไผ่ฉะนั้น",
  "165": "ตนทำบาปเอง ตนก็เศร้าหมองเอง ตนไม่ทำบาปตนก็บริสุทธิ์เอง ความบริสุทธิ์หรือไม่บริสุทธิ์เป็นของเฉพาะตน คนอื่นจะให้คนอื่นบริสุทธิ์แทนไม่ได้",
  "166": "ถึงจะทำประโยชน์แก่คนอื่นมากมาย ก็ไม่ควรละทิ้งจุดหมายปลายทางของตน เมื่อรู้ว่าอะไรคือจุดหมายปลายทางของตนแล้ว ก็ควรใฝ่ใจขวนขวาย",
  "chap13": "โลก",
  "167": "อย่าประพฤติสิ่งเลวทราม อย่าอยู่ด้วยความประมาท อย่ายึดถือความเห็นผิด อย่าทำตนเป็นคนรกโลก",
  "168": "ลุกขึ้นเถิด อย่ามัวประมาทอยู่เลย จงประพฤติสุจริตธรรม เพราะผู้ประพฤติธรรมย่อมอยู่เป็นสุข ทั้งในโลกนี้และโลกหน้า",
  "169": "จงประพฤติสุจริตธรรม อย่าประพฤติทุจริต ผู้ประพฤติธรรมย่อมอยู่เป็นสุข ทั้งในโลกนี้และโลกหน้า",
  "170": "ผู้ที่มองเห็นโลก ว่าไม่จีรังและหาสาระอะไรมิได้ เช่นเดียวกับคนมองฟองน้ำและพยับแดด คนเช่นนี้พญามารย่อมตามหาไม่พบ",
  "171": "สูเจ้าทั้งหลาย จงมาเถิดมาดูโลกนี้ อันวิจิตรพิสดาร เหมือนกับราชรถทรง ณ ที่นี่แหละ เหล่าคนโง่พากันหมกมุ่นอยู่ แต่ผู้รู้หาติดข้องอยู่ไม่",
  "172": "ผู้ที่เคยประมาทในกาลก่อน แต่ภายหลังไม่ประมาท เขาย่อมส่องโลกนี้ให้สว่าง เหมือนพระจันทร์ที่พ้นจากเมฆ",
  "173": "ผู้ใดทำบาปไว้แล้ว ละได้ด้วยการทำดี ผู้นั้นย่อมส่องโลกนี้ให้สว่าง เหมือนพระจันทร์ที่พ้นจากเมฆ",
  "174": "โลกนี้ มืดมน น้อยคนจักเห็นแจ้ง น้อยคน จะไปสวรรค์ เหมือนนกติดข่ายนายพราน น้อยตัวจะหลุดรอดไปได้",
  "175": "พระยาหงส์ เหินฟ้าไปหาพระอาทิตย์ ผู้มีฤทธิ์ เหาะเหินเดินอากาศ นักปราชญ์ ออกไปจากโลก เพราะเอาชนะพญามารพร้อมทั้งกองทัพ",
  "176": "คนที่ล่วงศีลข้อที่สี่ มักพูดเท็จ ไม่คำนึงถึงปรโลก จะไม่ทำความชั่ว ไม่มี",
  "177": "แน่นอน คนตระหนี่ไม่มีโอกาสไปเทวโลก แน่นอน คนโง่ ไม่สรรเสริญการให้ แต่คนฉลาด ยินดีให้ทาน นี่แลที่บันดาลให้เขาได้รับสุขในปรภพ",
  "178": "ยิ่งกว่า เอกราชย์ทั่วทั้งแผ่นดิน ยิ่งกว่า ขึ้นสวรรคาลัย ยิ่งกว่า อธิปไตยใดในโลกทั้งปวง คือ พระโสดาปัตติผล",
  "chap14": "พระพุทธเจ้า",
  "179": "พระพุทธเจ้าพระองค์ใด ทรงชนะกิเลสได้เด็ดขาด กิเลสที่ทรงชนะแล้วไม่ติดตามพระองค์ไปอีก พระพุทธเจ้าองค์นั้น ทรงมีพระสัพพัญญุตญาณหาที่สุดมิได้ ไม่ไปตามทางของกิเลสแล้ว พวกเธอจะนำท่านไปตามทางไหนเล่า",
  "180": "พระพุทธเจ้าพระองค์ใด ไม่มีตัณหาดังตาข่าย อันมีพิษสงร้ายกาจ พระพุทธเจ้าพระองค์นั้น ทรงมีพระสัพพัญญุตญาณหาที่สุดมิได้ ไม่ไปตามทางของกิเลสแล้ว พวกเธอจะนำท่านไปตามทางไหนเล่า",
  "181": "เหล่าเทวดาย่อมรักธีรชน ผู้ขวนขวายในกรรมฐาน ยินดีในนิพพานอันสงบ มีสติและรู้แจ้งจบสัจธรรม",
  "182": "ยาก ที่ได้เกิดมาเป็นมนุษย์ ยาก ที่ชีวิตสัตว์อยู่สบาย ยาก ที่จะได้ฟังธรรมของสัตบุรุษ ยาก ที่พระสัมพุทธจะอุบัติมา",
  "183": "ไม่ทำความชั่วทุกชนิด ทำแต่ความดี ทำใจให้ผ่องใส นี้เป็นคำสอนของพระพุทธเจ้าทั้งหลาย",
  "184": "ขันติคือความอดทน เป็นตบะอย่างยอด นิพพาน ท่านผู้รู้กล่าวว่าเป็นยอด ผู้ที่ยังทำร้ายผู้อื่นอยู่ ไม่จัดว่าเป็นบรรพชิต ผู้ที่ยังเบียดเบียนคนอื่นอยู่ ไม่จัดว่าเป็นสมณะ",
  "185": "ไม่ว่าร้ายใคร ไม่กระทบกระทั่งใคร ระมัดระวังในปาติโมกข์ บริโภคพอประมาณ อยู่ในสถานสงัด ฝึกหัดจิตให้สงบ นี้คือคำสอนของพระพุทธเจ้าทั้งหลาย",
  "186": "ถึงแม้เงินตราจะไหลมาดังห่าฝน ความอยากของคนก็หาอิ่มไม่ กามวิสัยทั้งหลายมีความสุขจริงๆ น้อย เต็มไปด้วยความทุกข์สารพัด",
  "187": "รู้ชัดดังนี้แล้ว สาวกของพระสัมมาสัมพุทธเจ้า ย่อมไม่ยินดีในกามารมณ์แม้ที่เป็นทิพย์ หากแต่ยินดีในทางสิ้นกิเลสตัณหา",
  "188": "คนเป็นจำนวนมาก เมื่อภัยมาถึงตัว พากันยึดเอาสิ่งต่างๆ เป็นที่พึ่ง อาทิ ภูเขา ป่าไม้ สวน ต้นไม้ และเจดีย์",
  "189": "นั่นมิใช่ที่พึ่งอันปลอดภัย นั่นมิใช่ที่พึ่งอันสูงสุด อาศัยที่พึ่งชนิดนั้น ก็ไม่พ้นทุกข์ทั้งปวงได้",
  "190": "ผู้ถึงพระพุทธ พระธรรม และพระสงฆ์เป็นที่พึ่ง ย่อมเห็นอริยสัจด้วยปัญญาอันชอบ คือ",
  "191": "ทุกข์, เหตุของทุกข์, ความดับทุกข์ และ อริยมรรคมีองค์แปด อันเป็นทางดับทุกข์",
  "192": "นั่นแลคือที่พึ่งอันปลอดภัย นั่นคือที่พึ่งอันสูงสุด คนเราอาศัยที่พึ่งชนิดนั้น ย่อมพ้นจากทุกข์ทั้งปวง",
  "193": "บุรุษอาชาไนย หาได้ยาก เขาย่อมไม่เกิดในตระกูลทั่วไป คนฉลาดเช่นนี้ เกิดในตระกูลใด ตระกูลนั้นย่อมเจริญรุ่งเรืองด้วยความสุข",
  "194": "การเกิดขึ้นของพระพุทธเจ้าทั้งหลายให้เกิดสุข การแสดงพระสัทธรรมให้เกิดสุข ความพร้อมเพรียงของหมู่ให้เกิดสุข ความพยายามของหมู่ที่พร้อมเพรียงกันให้เกิดสุข",
  "195": "ผู้บูชาท่านที่ควรบูชา คือพระพุทธเจ้า หรือสาวกของพระพุทธเจ้า ผู้ล่วงพ้นกิเลสเครื่องขวางกั้น หมดโศกหมดปริเทวนา สงบระงับ",
  "196": "ปลอดภัยโดยประการทั้งปวง ใครๆ ไม่สามารถจะคำนวณบุญของบุคคลผู้นี้ว่า 'เขาได้บุญประมาณเท่านี้'",
  "chap15": "ความสุข",
  "197": "ในหมู่มนุษย์ ผู้จองเวรกัน พวกเราไม่จองเวรใคร ช่างอยู่สบายจริงหนอ ในหมู่มนุษย์ผู้เต็มไปด้วยเวร พวกเราอยู่อย่างปราศจากเวร",
  "198": "ในหมู่มนุษย์ ผู้มีกิเลส พวกเราหมดกิเลสแล้ว ช่างอยู่สุขสบายจริงหนอ ในหมู่มนุษย์ ผู้มีกิเลส พวกเราอยู่ปราศจากกิเลส",
  "199": "ในหมู่มนุษย์ ผู้มีความกระวนกระวาย พวกเราไม่กระวนกระวาย ช่างอยู่เป็นสุขสบายจริงหนอ ในหมู่มนุษย์ ผู้มีความกระวนกระวาย พวกเราอยู่ปราศจากความกระวนกระวาย",
  "200": "พวกเราไม่มีกิเลสเศร้าหมองใจ ช่างอยู่สุขสบายจริงหนอ พวกเรามีปีติเป็นภักษาหาร เปรียบปานเหล่าอาภัสรพรหม",
  "201": "ผู้แพ้ย่อมก่อเวร ผู้พ่ายย่อมอยู่เป็นทุกข์ ผู้ละความแพ้และความพ่ายเสีย มีใจสงบระงับนั่นแหละเป็นสุข",
  "202": "ไม่มีไฟใดเสมอด้วยราคะ ไมีมีโทษใดเสมอด้วยโทสะ ไม่มีทุกข์ใดเสมอด้วยเบญจขันธ์ ไม่มีสุขใดเสมอด้วยความสงบ",
  "203": "ความหิวเป็นโรคอย่างยิ่ง สังขาร เป็นทุกข์อย่างยิ่ง รู้ความจริงข้อนี้แล้ว (คนฉลาด จึงทำพระนิพพานให้แจ้ง) พระนิพพาน เป็นสุขอย่างยิ่ง",
  "204": "ความไม่มีโรค เป็นลาภอย่างยิ่ง ความรู้จักพอ เป็นทรัพย์อย่างยิ่ง ความไว้วางใจกัน เป็นญาติอย่างยิ่ง พระนิพพาน เป็นสุขอย่างยิ่ง",
  "205": "เมื่อได้ลิ้มรสแห่งวิเวก และรสพระนิพพานอันสงบ ได้ดื่มรสแห่งความอิ่มเอมในพระธรรม บุคคลย่อมจะหมดบาป หมดทุกข์ร้อน",
  "206": "การพบพระอริยเจ้าเป็นความดี การอยู่ร่วมกับท่านให้เกิดสุขทุกเมื่อ เมื่อไม่คบคนพาลเสียได้ คนเราพึงมีความสุขเป็นนิจนิรันดร์",
  "207": "เพราะผู้คบคนพาล ย่อมเศร้าโศกนาน การอยู่ร่วมกับคนพาลมีแต่ความทุกข์ เหมือนอยู่ร่วมกับศัตรู การอยู่ร่วมกับนักปราญ์มีแต่ความสุข เหมือนสมาคมของญาติ",
  "208": "เพราะฉะนั้นจึงควรประพฤติตามผู้เป็นปราชญ์ ผู้เฉียบแหลม ศึกษาเล่าเรียนมาก มีศีลาจารวัตร เรียบร้อย เป็นพระอริยะ เป็นสัตบุรุษ มีปัญญาดี เหมือนพระจันทร์ไปตามทางของกลุ่มนักขัตฤกษ์",
  "chap16": "ความรัก",
  "209": "พยายามในสิ่งที่ไม่ควรพยายาม ไม่พยายามในสิ่งที่ควรพยายาม ละเลยสิ่งที่เป็นประโยชน์ ติดอยู่ในปิยารมณ์ คนเช่นนี้ก็ได้แต่ริษยาผู้ที่พยายามช่วยตัวเอง",
  "210": "อย่าติดอยู่ในสิ่งที่เรารัก หรือไม่รัก การพลัดพรากจากสิ่งที่เรารัก เป็นทุกข์ การพบเห็นแต่สิ่งที่ไม่รัก ก็เป็นทุกข์",
  "211": "เพราะฉะนั้น ไม่ควรรักสิ่งใด เพราะพลัดพรากจากของรัก เป็นทุกข์ ผู้ที่หมดความรักและความไม่รักแล้ว เครื่องผูกพัน ก็พลอยหมดไปด้วย",
  "212": "ที่ใดมีของรัก ที่นั่นมีโศก ที่ใดมีของรัก ที่นั่นมีภัย เมื่อไม่มีของรักเสียแล้ว โศกภัย ก็ไม่มี",
  "213": "ที่ใดมีความรัก ที่นั่นมีโศก ที่ใดมีความรัก ที่นั่นมีภัย เมื่อไม่มีความรักเสียแล้ว โศก ภัย ก็ไม่มี",
  "214": "ที่ใดมีความยินดี ที่นั่นมีโศก ที่ใดมีความยินดี ที่นั่นมีภัย เมื่อไม่มีความยินดีเสียแล้ว โศก ภัย ก็ไม่มี",
  "215": "ที่ใดมีความใคร่ ที่นั่นมีโศก ที่ใดมีความใคร่ ที่นั่นมีภัย เมื่อไม่มีความใคร่เสียแล้ว โศก ภัย ก็ไม่มี",
  "216": "ที่ใดมีความทะยานอยาก ที่นั่นมีโศก ที่ใดมีความทะยานอยาก ที่นั่นมีภัย เมื่อไม่มีความทะยานอยากเสียแล้ว โศก ภัย ก็ไม่มี",
  "217": "ผู้ประพฤติดี มีความเห็นถูกต้อง มั่นอยู่ในคลองธรรม พูดคำสัตย์ ปฏิบัติหน้าที่ของคนสมบูรณ์ คนย่อมเทิดทูนด้วยความรัก",
  "218": "พระอนาคามีผู้ใฝ่พระนิพพาน สัมผัสผ่านผลสามด้วยใจ หมดปฏิพัทธ์รักใคร่ในกาม จึงได้สมญานามว่า 'ผู้ทวนกระแส'",
  "219": "บุรษผู้จากไปนาน เมื่อกลับมาจากไพรัชสถานโดยสวัสดี ญาติ และมิตรสหายย่อมยินดีต้อนรับ",
  "220": "บุญที่ได้ทำไว้ในโลกนี้ ย่อมต้อนรับผู้ที่จากไป เหมือนญาติที่รักมาจากที่ไกล ฝูงชนย่อมเต็มใจต้อนรับ",
  "chap17": "ความโกรธ",
  "221": "ควรละความโกรธ และมานะ เอาชนะกิเลสเครื่องผูกมัดทุกชนิด ผู้ที่ไม่ติดอยู่ในรูปนาม หมดกิเลสแล้ว ย่อมคลาดแคล้วจากความทุกข์",
  "222": "ผู้ใดยับยั้งความโกรธที่เกิดขึ้นได้ทันที เหมือนสารถีหยุดรถที่กำลังแล่นไว้ได้ ผู้นั้นไซร้เราเรียกว่า 'สารถี' ส่วนคนนอกนี้ได้ชื่อเพียง 'ผู้ถือเชือก'",
  "223": "พึงเอาชนะความโกรธ ด้วยความไม่โกรธ พึงเอาชนะความร้าย ด้วยความดี พึงเอาชนะคนตระหนี่ ด้วยการให้ พึงเอาชนะคนพูดพล่อย ด้วยคำสัตย์",
  "224": "ควรพูดคำสัตย์จริง ไม่ควรโกรธ แม้เขาขอเล็กๆ น้อยๆ ก็ควรให้ ด้วยการปฏิบัติทั้งสามนี้ เขาก็อาจไปสวรรค์ได้",
  "225": "พระมุนี ผู้ไม่เบียดเบียนใคร ควบคุมกายอยู่เป็นนิจศีล ย่อมไปยังถิ่นที่นิรันดร ที่สัญจรไปแล้ว ไม่เศร้าโศก",
  "226": "สำหรับท่านผู้ตื่นอยู่ตลอดเวลา สำเหนียกศึกษาทุกทิพาราตรี มีใจน้อมไปสู่พระนิพพาน อาสวะย่อมอันตรธานหมดสิ้น",
  "227": "อตุลเอย เรื่องอย่างนี้มีมานานแล้ว มิใช่เพิ่งจะมีในปัจจุบันนี้ อยู่เฉยๆ เขาก็นินทา พูดมาก เขาก็นินทา พูดน้อย เขาก็นินทา ไม่มีใครในโลก ที่ไม่ถูกนินทา",
  "228": "ไม่ว่าในอดีต ปัจจุบัน อนาคต คนที่ถูกสรรเสริญ โดยส่วนเดียว หรือถูกนินทา โดยส่วนเดียว ไม่มี",
  "229": "นักปราชญ์พิจารณารอบคอบแล้ว จึงสรรเสริญผู้ใด ผู้ดำเนินชีวิตหาที่ติมิได้ ฉลาด สมบูรณ์ด้วยปัญญาและศีล",
  "230": "ผู้นั้น เปรียบเสมือนแท่งทองบริสุทธิ์ ใครเล่าจะตำหนิเขาได้ คนเช่นนี้ แม้เทวดาก็ชม ถึงพรหม ก็สรรเสริญ",
  "231": "พึงควบคุม ความคะนองทางกาย พึงสำรวม การกระทำทางกาย พึงละกายทุจริต ประพฤติกายสุจริต",
  "232": "พึงควบคุม ความคนองทางวาจา พึงสำรวม คำพูด พึงละวจีทุจริต ประพฤติวจีสุจริต",
  "233": "พึงควบคุม ความคะนองทางใจ พึงสำรวม ความคิด พึงละมโนทุจริต ประพฤติมโนสุจริต",
  "234": "ผู้มีปัญญา ย่อมสำรวมกาย วาจา ใจ ท่านเหล่านั้น นับว่า ผู้สำรวมดีแท้จริง",
  "chap18": "มลทิน",
  "235": "บัดนี้ เธอแก่ดังใบไม้เหลือง ยมทูตกำลังเฝ้ารออยู่ เธอกำลังจะจากไปไกล แต่เสบียงเดินทางของเธอไม่มี",
  "236": "เธอจงสร้างที่พึ่งแก่ตนเอง รีบพยายามขวนขวายหาปัญญาใส่ตัว เมื่อเธอหมดมลทิน หมดกิเลสแล้ว เธอก็จักเข้าถึงทิพยภูมิของพระอริยะ",
  "237": "บัดนี้ เธอใกล้จะถึงอายุขัยแล้ว เธอย่างเข้าใกล้สำนักพญามัจจุราชแล้ว ที่พักระหว่างทางของเธอก็ไม่มี เสบียงเดินทาง เธอก็ไม่ได้หาไว้",
  "238": "จงสร้างที่พึ่งแก่ตัวเอง รีบขวนขวายหาปัญญาใส่ตัว เมื่อเธอหมดมลทิน หมดกิเลสแล้ว เธอก็จักไม่มาเกิดมาแก่อีกต่อไป",
  "239": "คนมีปัญญา ควรขจัดมลทินของตน ทีละน้อยๆ ทุกๆ ขณะ โดยลำดับ เหมือนนายช่างทอง ปัดเป่าสนิมแร่",
  "240": "สนิมเกิดแต่เหล็ก กัดกินเหล็กฉันใด กรรมที่ตนทำไว้ ย่อมนำเขาไปทุคติฉันนั้น",
  "241": "ความเสื่อมของมนตรา อยู่ที่การไม่ทบทวน ความเสื่อมของเรือน อยู่ที่ไม่ซ่อมแซม ความเสื่อมของความงาม อยู่ที่เกียจคร้านตบแต่ง ความเสื่อมของนายยาม อยู่ที่ความเผลอ",
  "242": "ความประพฤติเสียหาย เป็นมลทินของสตรี ความตระหนี่ เป็นมลทินของผู้ให้ ความชั่วทุกชนิด เป็นมลทิน ทั้งในโลกนี้ และโลกหน้า",
  "243": "มลทินที่ยิ่งใหญ่กว่านั้น คือความโง่เขลา ความโง่เขลา นับเป็นมลทินชั้นยอด ภิกษุทั้งหลายพวกเธอจงละมลทินชนิดนี้ เป็นผู้ปราศจากมลทินเถิด",
  "244": "คนไร้ยางอาย กล้าเหมือนกา ชอบทำลายผู้อื่นลับหลัง ชอบเอาหน้า อวดดี มีพฤติกรรมสกปรก คนเช่นนี้ เป็นอยู่ง่าย",
  "245": "ส่วนคนที่มีหิริ ใฝ่ความบริสุทธิ์เป็นนิตย์ ไม่เกียจคร้าน อ่อนน้อมถ่อมตน มีความเป็นอยู่บริสุทธิ์ มีปัญญา คนเช่นนี้เป็นอยู่ลำบาก",
  "246": "ผู้ใด ฆ่าสัตว์ พูดเท็จ ลักทรัพย์ ประพฤติล่วงเกินภรรยาของผู้อื่น",
  "247": "ดื่มสุราเมรัยเป็นนิจศีล ผู้นั้นนับว่าขุดรากถอนโคนตนเองในโลกนี้ทีเดียว",
  "248": "จงรู้เถิด บุรุษผู้เจริญเอ๋ย ความชั่วร้าย มิใช่สิ่งที่จะพึงควบคุมได้ง่ายๆ ขอความโลภและความชั่วช้า อย่าได้ฉุดกระชากเธอ ไปหาความทุกข์ตลอดกาลนานเลย",
  "249": "ประชาชนย่อมให้ทานตามศรัทธา ใครคิดอิจฉาในข้าวและน้ำของคนอื่น เขาย่อมไม่ได้รับความสงบใจ ไม่ว่ากลางวัน หรือ กลางคืน",
  "250": "ผู้ใดเลิกคิดเช่นนั้นแล้ว ผู้นั้น ย่อมได้รับความสงบใจ ทั้งในกลางวันและกลางคืน",
  "251": "ไม่มี ไฟใด เสมอราคะ ไม่มี เคราะห์ใด เสมอโทสะ ไม่มี ข่ายดักสัตว์ใด เสมอโมหะ ไม่มี แม่น้ำใด เสมอตัณหา",
  "252": "โทษคนอื่นเห็นได้ง่าย โทษตนเห็นได้ยาก คนเรามักเปิดเผยโทษคนอื่น เหมือนโปรยแกลบ แต่ปิดบังโทษของตน เหมือนนักเลงเต๋าโกงซ่อนลูกเต๋า",
  "253": "ผู้ที่เพ่งแต่โทษคนอื่น คอยจับผิดอยู่ตลอดเวลา เขาย่อมหนาด้วยกิเลสอาสวะ ไม่มีทางเลิกละมันได้",
  "254": "ไม่มีรอยเท้าในอากาศ ไม่มีสมณะภายนอกศาสนานี้ สัตว์พากันยินดีในกิเลสที่กีดขวางนิพพาน พระตถาคตทั้งหลาย หมดกิเลสชนิดนั้นแล้ว",
  "255": "ไม่มี รอยเท้าในอากาศ ไม่มี สมณะนอกศาสนานี้ ไม่มี สังขารที่เที่ยงแท้ ไม่มี ความหวั่นไหวสำหรับพระพุทธเจ้า",
  "chap19": "เที่ยงธรรม",
  "256": "ผู้ที่ตัดสินความโดยหุนหันพลันแล่น ไม่จัดเป็นผู้เที่ยงธรรม ส่วนผู้ที่ฉลาด วินิจฉัยรอบคอบ ทั้งฝ่ายถูก และฝ่ายผิด (จึงจัดเป็นผู้เที่ยงธรรม)",
  "257": "บัณฑิตผู้ตัดสินผู้อื่นโดยรอบคอบ โดยเที่ยงธรรมสม่ำเสมอ ถือความถูกต้องเป็นใหญ่ ผู้นี้ได้สมญาว่า ผู้เที่ยงธรรม",
  "258": "เพียงแต่พูดมาก ไม่จัดว่าเป็นบัณฑิต คนที่ประพฤติตนให้เกษม ไม่มีเวร ไม่มีภัย จึงจะเรียกว่า เป็นบัณฑิต",
  "259": "บุคคลไม่นับว่าผู้ทรงธรรม ด้วยเหตุเพียงพูดมาก ส่วนผู้ใด ถึงได้สดับตรับฟังน้อย แต่เห็นธรรมด้วยใจ ไม่ประมาทในธรรม ผู้นั้นแล เรียกว่า ผู้ทรงธรรม",
  "260": "เพียงมีผมหงอก ยังไม่นับว่า เถระ เขาแก่แต่วัยเท่านั้น เรียกได้ว่า คนแก่เปล่า",
  "261": "ผู้ใดมี สัจจะ คุณธรรม ไม่เบียดเบียน สำรวม ข่มใจ ฉลาด ปราศจากมลทินโทษ ผู้นั้นแล เรียกว่า เถระ",
  "262": "ไม่ใช่เพราะพูดคล่อง ไม่ใช่เพราะมีผิวพรรณสวย ที่ทำให้คนเป็นคนดีได้ ถ้าหากเขายังมีความริษยา มีความตระหนี่ เจ้าเล่ห์ (เขาก็เป็นคนดีไม่ได้)",
  "263": "ผู้ใดเลิกละความอิจฉาเป็นต้น ได้อย่างเด็ดขาดแล้ว คนฉลาด ปราศจากมลทินเช่นนี้ เรียกว่า คนดี",
  "264": "คนศีรษะโล้นไร้ศีลวัตร พูดเท็จ ไม่นับเป็นสมณะ เขามีแต่ความอยากและความโลภ จักเป็นสมณะได้อย่างไร",
  "265": "ผู้ที่ระงับบาปทั้งหลาย ทั้งน้อยและใหญ่ เรียกว่าเป็นสมณะ เพราะเลิกละบาปได้",
  "266": "เพียงขอภิกษาจากผู้อื่น ไม่ชื่อว่าเป็นภิกษุ ถ้ายังประพฤติตนเหมือนชาวบ้านอยู่ ก็ยังไม่ชื่อว่าเป็นภิกษุ",
  "267": "ผู้ใดละบุญละบาปทุกชนิด ครองชีวิตประเสริฐสุด อยู่ในโลกมนุษย์ด้วยปัญญา ผู้นี้แลเรียกว่า ภิกษุ",
  "268": "คนโง่เขลา ไม่รู้อะไร นั่งนิ่งดุจคนใบ้ ไม่นับเป็นมุนี ส่วนคนมีปัญญาทำตนเหมือนถือคันชั่ง เลือกชั่งเอาแต่ความดี ละทิ้งความชั่วช้า",
  "269": "ด้วยปฏิปทาดังกล่าวเขานับว่าเป็นมุนี อนึ่งผู้ที่รู้ทั้งโลกนี้และโลกหน้า จึงควรแก่สมญาว่า มุนี",
  "270": "ถ้ายังเบียดเบียนสัตว์อยู่ บุคคลไม่นับว่า เป็นอารยชน เพราะไม่เบียดเบียนสัตว์ทั้งปวง เขาจึงได้ชื่อว่า อารยชน",
  "271": "ภิกษุเอย เพียงมีศีลาจารวัตร เพียงมีภูมิปริยัติคงแก่เรียน เพียงพากเพียรปฏิบัติจนได้ฌาน เพียงอยู่ในสถานสงบสงัด",
  "272": "ถ้าขจัดกิเลสไม่ได้หมด เธออย่านิ่งนอนใจ ว่า เธอได้รับสุขในบรรพชา ที่สามัญชนทั่วไปมิได้สัมผัส",
  "chap20": "ทาง",
  "273": "ยอดแห่งมรรคา คืออัษฎางคิกมรรค ยอดแห่งสัจจะ คืออริยสัจสี่ประการ ยอดแห่งธรรม คือความปราศจากราคะ ยอดแห่งมนุษย์ คือพระผู้เห็นแจ้ง",
  "274": "มีทางนี้เท่านั้น ไม่มีทางอื่น ที่จะนำไปสู่ความบริสุทธิ์แห่งทัศนะ พวกเธอจงเดินตามทางนี้เถิด ทางสายนี้พญามารมักเดินหลงเสมอ",
  "275": "เมื่อเดินตามทางสายนี้ พวกเธอจักหมดทุกข์ ทางสายนี้ เราได้ชี้บอกไว้ หลังจากที่เราได้รู้วิธีถอนลูกศรคือกิเลส",
  "276": "พวกเธอจงพยายามทำความเพียรเถิด พระตถาคต เป็นเพียงผู้ชี้บอกทางเท่านั้น ผู้บำเพ็ญฌานเดินตามทางสายนี้ ก็จะพ้นจากเครื่องผูกของพญามาร",
  "277": "'สังขารทั้งปวง ไม่เที่ยงแท้' เมื่อใด บุคคลเห็นแจ้งด้วยปัญญาดังนี้ เมื่อนั้น เขาย่อมหน่ายในทุกข์ นี้เป็นทางแห่งความบริสุทธิ์",
  "278": "'สังขารทั้งปวง เป็นทุกข์' เมื่อใด บุคคลเห็นแจ้งด้วยปัญญาดังนี้ เมื่อนั้น เขาย่อมหน่ายในทุกข์ นี่เป็นทางแห่งความบริสุทธิ์",
  "279": "'ธรรมทั้งปวง เป็นอนัตตา' เมื่อใด บุคคลเห็นแจ้งด้วยปัญญาดังนี้ เมื่อนั้น เขาย่อมหน่ายในทุกข์ นี่เป็นทางแห่งความบริสุทธิ์",
  "280": "คนเราเมื่อยังหนุ่มแน่น แข็งแรงแต่เกียจคร้าน ไม่ขยันในเวลาที่ควรขยัน มีความคิดตกต่ำ คนเกียจคร้านเฉื่อยชาเช่นนี้ ย่อมไม่พบทางแห่งปัญญา",
  "281": "พึงระวังวาจา พึงสำรวมใจ ไม่พึงทำบาปทางกาย พึงชำระทางกรรมทั้งสามนี้ให้หมดจด เมื่อทำได้เช่นนี้ เขาพึงพบทาง ที่พระพุทธเจ้าทั้งหลายแสดงไว้",
  "282": "ปัญญาเกิดมีได้ เพราะตั้งใจพินิจ เสื่อมไป เพราะไม่ได้ตั้งใจพินิจ เมื่อรู้ทางเจริญและทางเสื่อมของปัญญาแล้ว ควรจะทำตนโดยวิถีทางที่ปัญญาจะเจริญ",
  "283": "ภิกษุทั้งหลาย พวกเธอจงถางป่า (ราคะ) แต่อย่าตัดต้นไม้ (จริงๆ) ภัยย่อมเกิดจากป่า (ราคะ) พวกเธอทำลายป่า และพุ่มไม้เล็กๆ (ราคะ) ได้แล้ว จักเป็นผู้ไม่มีป่า (ราคะ)",
  "284": "ตราบใดบุรุษยังตัดความกำหนัด ต่ออิสตรีแม้นิดหน่อยยังไม่ขาด ตราบนั้น เขาก็ยังคงมีจิตผูกพันอยู่ในภพ เหมือนลูกโคยังไม่หย่านมติดแม่โคแจฉะนั้น",
  "285": "จงถอนความรักของตน เหมือนคนถอนดอกบัวที่เกิดในฤดูสารท จงเพิ่มพูนแนวทางแห่งสันติ คือ นิพพาน ที่พระสุคตเจ้าทรงแสดงไว้แล้ว",
  "286": "'เราจักอยู่ที่นี่ตลอดฤดูฝน เราจักอยู่ที่นี่ตลอดฤดูหนาว และฤดูร้อน' คนโง่มักคิดเช่นนี้ หารู้อันตรายจะมาถึงตัวเองไม่",
  "287": "ผู้ที่มัวเมาอยู่ในบุตรและปศุสัตว์ มีมนัสติดข้องอยู่ ย่อมถูกมฤตยูฉุดคร่าไป เหมือนชาวบ้านที่หลับใหล ถูกกระแสน้ำใหญ่พัดพา",
  "288": "บุตรก็ป้องกันไม่ได้ บิดาหรือญาติก็ป้องกันไม่ได้ คนเราเมื่อถึงคราวจะตาย หมู่ญาติก็ป้องกันไม่ได้",
  "289": "เมื่อรู้ความจริงข้อนี้แล้ว คนฉลาดผู้สำรวมในศีล ไม่ควรชักช้า ในการตระเตรียมทาง ไปสู่พระนิพพาน",
  "chap21": "เบ็ดเตล็ด",
  "290": "ถ้าเห็นว่า จะได้สุขอันยิ่งใหญ่ ด้วยการสละสุขเล็กๆ น้อยๆ นักปราชญ์ก็ควรสละสุขเล็กน้อย เพื่อเห็นแก่สุขอันยิ่งใหญ่",
  "291": "ผู้ใดปรารถนาสุขเพื่อตน โดยการก่อทุกข์ให้คนอื่น ผู้นั้นมักเกี่ยวพันด้วยเวรไม่รู้สิ้น ไม่มีทางพ้นทางเวรไปได้",
  "292": "สิ่งที่ควรทำไม่ทำ กลับทำสิ่งที่ไม่ควรทำ อาสวะย่อมเจริญแก่พวกเขา ผู้ถือตัวและมัวเมาประมาท",
  "293": "ส่วนชนเหล่าใด เจริญสติในกายเป็นนิตย์ ไม่ทำสิ่งที่ไม่ควรทำ ทำเฉพาะสิ่งที่ควรทำเสมอ สำหรับชนผู้มีสติ สัมปชัญญะพร้อมมูลเหล่านั้น อาสวะมีแต่จะหมดไป",
  "294": "พราหมณ์ฆ่ามารดา ฆ่าบิดา ฆ่าขัตติยราชอีกสององค์ ทำลายรัฐ พร้อมทั้งผู้ครองรัฐเสียแล้ว ย่อมสัญจรไป อย่างไร้ทุกข์",
  "295": "พราหมณ์ฆ่ามารดา ฆ่าบิดา ฆ่ากษัตริย์ ผู้คงแก่เรียนอีกสององค์ ทำลายทางเดินห้าสายของพยัคฆ์ร้าย ย่อมสัญจรไป อย่างปลอดภัย",
  "296": "พระสาวกของพระโคดมพุทธเจ้า ผู้รำลึกถึงพระพุทธคุณ เป็นนิจศีล ทั้งกลางวันกลางคืน ตื่นดีแล้วเสมอ",
  "297": "พระสาวกของพระโคดมพุทธเจ้า ผู้รำลึกถึงพระธรรมคุณ เป็นนิจศีลทั้งกลางวันกลางคืน ตื่นดีแล้วเสมอ",
  "298": "พระสาวกของพระโคดมพุทธเจ้า ผู้ระลึกถึงพระสังฆคุณ เป็นนิจศีลทั้งกลางวันกลางคืน ตื่นดีแล้วเสมอ",
  "299": "พระสาวกของพระโคดมพุทธเจ้า ผู้รำลึกถึงสภาพเป็นจริงของร่างกาย เป็นนิจศีลทั้งกลางวันกลางคืน ตื่นดีแล้วเสมอ",
  "300": "พระสาวกของพระโคดมพุทธเจ้า ผู้มีใจยินดีในความไม่เบียดเบียน เป็นนิจศีลทั้งกลางวันกลางคืน ตื่นดีแล้วเสมอ",
  "301": "พระสาวกของพระโคดมพุทธเจ้า ผู้มีใจยินดีในภาวนา เป็นนิจศีลทั้งกลางวัน กลางคืน ตื่นดีแล้วเสมอ",
  "302": "การสละโลกียวิสัยออกบวช ก็ยาก การจะยินดีในเพศบรรพชิต ก็ยาก การครองเรือนไม่ดี เป็นทุกข์ การอยู่ร่วมกับผู้ไม่เสมอกัน ก็เป็นทุกข์ ท่องเที่ยวอยู่ในสังสารวัฏ ก็เป็นทุกข์ เพราะฉะนั้น ไม่ควรท่องเที่ยวในสังสารวัฏ และไม่ควรแส่หาความทุกข์ใส่ตน",
  "303": "ผู้มีศรัทธา สมบูรณ์ด้วยศีล เพียบพร้อมด้วยยศและโภคทรัพย์ ไปประเทศใดๆ ย่อมได้รับความนับถือ ในประเทศนั้นๆ",
  "304": "คนดี ย่อมปรากฏเด่น เหมือนภูเขาหิมพานต์ คนไม่ดี ถึงอยู่ใกล้ ก็ไม่ปรากฏ เหมือนลูกศรที่เขายิงไปในราตรี",
  "305": "นั่งอยู่คนเดียว นอนอยู่คนเดียว เดินไปคนเดียวโดยไม่เกียจคร่าน คนเดียวควบคุมตนเอง หาความสุขในป่า",
  "chap22": "นรก",
  "306": "คนที่พูดเท็จเสมอ กับคนที่ทำแล้ว พูดว่า 'ฉันไม่ได้ทำ' ตกนรกเหมือนกัน มนุษย์สองจำพวกนั้น ตายไปแล้ว มีกรรมชั่วเหมือนกัน ในโลกหน้า",
  "307": "คนนุ่งห่มผ้ากาสาวพัสตร์มีเป็นจำนวนมาก ที่ประพฤติชั่ว ไม่สำรวม คนชั่วเหล่านั้นย่อมตกนรก เพราะกรรมชั่ว",
  "308": "คนทุศีล ไม่สำรวม กลืนก้อนเหล็กแดงที่ลุกเป็นไฟ ยังดีเสียกว่าบริโภคข้าว ที่ชาวบ้านถวาย",
  "309": "คนที่มัวเมา ผิดเมียท่านเป็นนิตย์ ย่อมได้รับเคราะห์ร้าย สี่สถานคือ หนึ่งได้รับบาป สองนอนไม่เป็นสุข สามเสียชื่อเสียง สี่ตกนรก",
  "310": "สถานหนึ่ง ได้บาป สถานสอง ได้ภพชาติชั่วร้ายในอนาคต สถานสาม ทั้งคู่มีสุขชั่วแล่นแต่สะดุ้งใจเป็นนิตย์ สถานสี่ พระราชาย่อมลงโทษอย่างหนัก เพราะฉะนั้น จึงไม่ควรผิดภริยาของคนอื่น",
  "311": "หญ้าคา ที่จับไม่ดี ย่อมบาดมือได้ ฉันใด พรหมจรรย์ที่ประพฤติไม่ดี ย่อมลากลงสู่นรก ฉันนั้น",
  "312": "ทำอะไรหละหลวม มีข้อวัตรปฏิบัติเศร้าหมอง ประพฤติพรฟมจรรย์ โดยไม่เต็มใจ ไม่เป็นไปเพื่อผลอันไพศาล",
  "313": "ถ้าจะกระทำ ก็จงกระทำจริงๆ และพยายามมั่นคงจริงๆ เพราะเพศบรรพชิตที่หละหลวม รังแต่จะเกลี่ยธุลีคือกิเลสใส่ตัว",
  "314": "ความชั่ว ไม่ทำเสียเลยเป็นดี ทำแล้วย่อมเดือดร้อนภายหลัง มาทำความดีกันดีกว่า ทำแล้ว ไม่เดือดร้อน",
  "315": "เธอจงป้องกันตนให้ดีเหมือนเมืองชายแดน ที่เขาป้องกันแข็งแรงทั้งภายในภายนอก เธออย่าปล่อยโอกาสให้ล่วงเลยไปเปล่า เพราะผู้ที่พลาดโอกาสเมื่อตกนรกย่อมเศร้าโศก",
  "316": "ละอายในสิ่งที่ไม่ควรละอาย ไม่ละอายในสิ่งที่ควรละอาย ผู้ที่มีความเห็นผิดอย่างนี้ ย่อมไปสู่ทุคติ",
  "317": "สิ่งที่ไม่น่ากลัว เห็นว่าน่ากลัว สิ่งที่น่ากลัว กลับเห็นว่า ไม่น่ากลัว ผู้ที่มีความเห็นผิดอย่างนี้ ย่อมไปทุคติ",
  "318": "สิ่งที่ไม่มีโทษ เห็นว่ามีโทษ สิ่งที่มีโทษ กลับเห็นว่าไม่มีโทษ ผู้ที่มีความเห็นผิดอย่างนี้ ย่อมไปสู่ทุคติ",
  "319": "เห็นโทษ เป็นโทษ เห็นถูก เป็นถูก ผู้ที่มีความเห็นชอบเช่นนี้ ย่อมไปสู่สุคติ",
  "chap23": "ช้าง",
  "320": "เราจักอดทนต่อคำเสียดสีของคนอื่น เหมือนพญาคชสาร ในสนามรบ ทนลูกศรที่ปล่อยออกไปจากคันธนู เพราะว่าคนโดยมาก ทุศีล",
  "321": "ช้างที่ฝึกแล้ว เขานำไปสู่ที่ชุมชน ช้างที่ฝึกแล้ว พระราชาขึ้นทรง ในหมู่มนุษย์ ผู้ที่ฝึกฝนตนได้ รู้จักอดทนต่อคำล่วงเกิน เป็นผู้ประเสริฐ",
  "322": "ม้าอัศดร ม้าอาชาไนยจากกลุ่มสินธู และพญากุญชร ที่ผ่านการฝึกปรือ นับเป็นสัตว์ที่ประเสริฐ แต่บุคคลผู้ฝึกตนแล้ว ประเสริฐกว่านั้น",
  "323": "แน่นอนทีเดียว คนที่ฝึกตนได้ ย่อมอาศัยร่างที่ฝึกฝนดีแล้วนั้น เป็นพาหนะนำไปสู่ที่ๆ ไม่เคยไป (นิพพาน) ซึ่งยานภายนอกเหล่านั้น พาไปไม่ได้เลย",
  "324": "ช้างตกมันชื่อ ธนปาลกะ ยากที่ใครๆ จะห้ามได้ ถูกล่ามไว้ ไม่ยอมกินอาหาร พญากุญชร รำลึกถึงแต่ป่าช้าง",
  "325": "คนกินจุ สะลึมสะลือ ชอบนอน กลิ้งเกลือกไปมาบนที่นอน เหมือนสุกรที่เขาขุนด้วยเศษอาหาร คนโง่ทึ่มเช่นนั้น ย่อมเกิดไม่รู้จบสิ้น",
  "326": "เมื่อก่อนใจข้าได้ท่องเที่ยวไปในอารมณ์ ตามปรารถนา ตามความใคร่ ตามสบาย แต่บัดนี้ ข้าจักบังคับมันด้วยโยนิโสมนสิการ เหมือนควาญช้างถือขอ บังคับช้างที่ตกมัน",
  "327": "พวกเธอจงยินดีในความไม่ประมาท จงระมัดระวังจิตของตน จงถอนตนออกจากหล่มกิเลส เหมือนพญาช้างติดหล่ม พยายามช่วยตัวเอง",
  "328": "ถ้าได้สหายผู้เข้ากับตนได้ มีความประพฤติดี ฉลาดและเฉลียว พึงไปไหนๆ กับสหายเช่นนั้นอย่างมีความสุข และพึงมีสติ ฝ่าฟันอันตรายทั้งหลาย",
  "329": "ถ้าไม่พบสหายที่เข้ากับตนได้ มีความประพฤติดี ฉลาด และเฉลียว ก็ควรสัญจรไปคนเดียว เหมือนพระราชา สละราชสมบัติเที่ยวไปองค์เดียว หรือไม่ก็เหมือนพญาช้าง ละโขลงเที่ยวไปตัวเดียวในป่า",
  "330": "เที่ยวไปคนเดียว ประเสริฐกว่า ความเป็นสหายในคนพาล ไม่มี พึงเที่ยวไปคนเดียว และไม่พึงทำบาป ไม่ดิ้นรนขวนขวายมาก เหมือนพญาช้างเที่ยวไปตัวเดียวในป่า",
  "331": "มีเพื่อนตาย ก็มีความสุข ยินดีเท่าที่หามาได้ ก็มีความสุข ทำบุญไว้ถึงคราวจะตายก็มีความสุข ละทุกข์ได้ทั้งหมด ก็มีความสุข",
  "332": "ปฏิบัติชอบต่อมารดา ก็เป็นสุข ปฏิบัติชอบต่อบิดา ก็เป็นสุข ปฏิบัติชอบต่อสมณะ ก็เป็นสุข ปฏิบัติชอบต่อพระผู้ประเสริฐ ก็เป็นสุข",
  "333": "ศีลให้เกิดสุข ตราบเท่าชรา ศรัทธา ที่ตั้งมั่นแล้ว ให้เกิดสุข ปัญญา ได้มาแล้ว ให้เกิดสุข การไม่ทำบาปทั้งหลาย ให้เกิดสุข",
  "chap24": "ตัณหา",
  "334": "สำหรับคนที่มีชีวิตอยู่อย่างประมาท ตัณหามีแต่จะเจริญเหมือนเถาวัลย์ เขาย่อมกระโดดจากภพนี้ไปสู่ภพอื่น เหมือนวานรโลภผลไม้ โลดแล่นอยู่ในป่า",
  "335": "ตัณหาอันลามก มีพิษร้าย ครอบงำบุคคลใด ในโลก เขาย่อมมีแต่โศกเศร้าสลด เหมือนหญ้าถูกฝนรด ย่อมงอกงาม",
  "336": "ผู้ใดเอาชนะตัณหาลามก ที่ยากจะเอาชนะได้นี้ ความโศกย่อมตกไปจากผู้นั้น เหมือนหยาดน้ำ ตกจากใบบัว",
  "337": "เราขอบอกความนี้แก่พวกเธอ ขอให้พวกเธอผู้มาชุมนุมกัน ณ ที่นี้ มีความเจริญ ขอให้พวกเธอขุดรากตัณหา เหมือนถอนรากหญ้ารก พวกเธออย่าปล่อยให้มารรังควาญบ่อยๆ เหมือนกระแสน้ำค่อยๆ เซาะต้อนอ้อล้ม",
  "338": "เมื่อรากยังแข็งแรง ไม่ถูกทำลาย ต้นไม้แม้ที่ถูกตัดแล้ว ก็งอกได้ใหม่ฉันใด เมื่อยังทำลายเชื้อตัณหาไม่ได้หมด ความทุกข์นี้ก็ย่อมเกิดขึ้นได้เรื่อยไปฉันนั้น",
  "339": "กระแสตัณหา ๓๖ สายอันเชี่ยวกราก ที่ไหลไปยังอารมณ์อันน่าปรารถนา ไหลบ่าท่วมท้นจิตใจใคร ความครุ่นคิดคำนึงที่แฝงราคะ ย่อมจะชักนำให้เขาเห็นผิดคิดไข้วเขว",
  "340": "กระแสน้ำคือตัณหา ไหลไปทุกหนทุกแห่ง เถาวัลย์คือกิเลส ก็ขึ้นรกไปทั่ว เมื่อเห็น เถาวัลย์นั้นงอกงามแล้ว พวกเธอจงตัดรากมันด้วยมีดคือปัญญา",
  "341": "สัตว์ทั้งหลาย มีแต่โสมนัส ชุ่มชื้นไปด้วยรักเสน่หา ซาบซ่านในกามารมณ์ทั้งปวง พวกเขาใฝ่แสวงแต่ความสุขสันต์หรรษา ก็ต้องเกิดต้องแก่อยู่ร่ำไป",
  "342": "เหล่าสัตว์ ติดกับตัณหา การเสือกกระสน ดุจกระต่ายติดบ่วง สัตว์ทั้งหลายติดอยู่ในกิเลสเครื่องผูกมัด ย่อมประสบทุกข์บ่อยๆ ตลอดกาลนาน",
  "343": "เหล่าสัตว์ ติดกับตัณหา กระเสือกกระสน ดุจกระต่ายติดบ่วง ฉะนั้นภิกษุ เมื่อหวังให้กิเลสจางคลาย ก็พึงทำลายตัณหาเสีย",
  "344": "บุคคลใดสละเพศผู้ครองเรือน ถือเพศบรรพชิตปราศจากเรือน พ้นจากป่ากิเลสแล้วยังวิ่งกลับไปหาป่านั้นอีก พวกเธอจงดูบุคคลนั้นเถิด เขาออกจากที่คุมขังแล้วยังวิ่งกลับเข้าที่คุมขังอีก",
  "345": "เครื่องจองจำที่ทำด้วยเหล็ก ไม้ และปอป่าน ท่านผู้รู้กล่าวว่า ยังไม่ใช่เครื่องจองจำที่มั่นคง แต่ความกำหนัดยินดีในเครื่องเพชร บุตร ภริยา เป็นเครื่องจองจำที่มั่นคงยิ่งนัก",
  "346": "ท่านผู้รู้กล่าวว่า เครื่องจองจำชนิดนี้มั่นคง มักฉุดลากลงที่ต่ำ คล้ายผูกไว้หลวมๆแต่แก้ยากนัก ผู้รู้ทั้งหลายจึงทำลายเครื่องจองจำนี้เสีย ละกามสุขออกบวชโดยไม่ไยดี",
  "347": "ผู้ถูกราคะครอบงำ ย่อมถลำลงสู่กระแสตัณหา เหมือนแมลงมุมตกลงไปยังใยที่ตนถักไว้เอง ผู้ฉลาดทั้งหลาย จึงทำลายเครื่องจองจำนี้ ละทุกข์ทั้งปวง ออกบวชโดยไม่ไยดี",
  "348": "จงปล่อยวางทั้งอดีตอนาคตและปัจจุบัน และอยู่เหนือความมีความเป็น เมื่อใจหลุดพ้นจากทุกอย่างแล้ว พวกเธอจักไม่เกิดไม่แก่อีกต่อไป",
  "349": "ผู้เป็นทาสวิตกจริต มีจิตกำหนัดยินดี ติดอยู่ในสิ่งที่สวยงาม มีแต่จะพอกความอยากให้หนา กระชับเครื่องพันธนาการให้แน่นเข้า",
  "350": "ผู้ตั้งใจระงับความคิดฟุ้งซ่าน เจริญอสุภกรรมฐานวิธี มีสติทุกเวลา จักขจัดตัณหาหมดสิ้นไป ทำลายเครื่องผูกของมาร",
  "351": "พระอรหันตฺผู้ลุถึงจุดหมายปลายทางแล้ว หมดความสุดุ้ง หมดกิเลสตัณหาแล้ว หักลูกศรคือกิเลสประจำภพแล้ว ร่างกายนี้เป็นร่างสุดท้ายของท่าน",
  "352": "หมดตัณหา ไม่ยึดมั่น ฉลาดในนิรุกติ รู้กลุ่มอักษรและรู้ลำดับหน้าหลัง ท่านผู้มีสรีระสุดท้ายนี้แล เรียกว่า มหาปราชญ์ และ มหาบุรุษ",
  "353": "เราเอาชนะทุกอย่าง เราตรัสรู้ทุกอย่าง เรามิได้ติดในทุกอย่าง เราละได้ทุกอย่าง เราเป็นอิสระเพราะสิ้นตัณหา เราตรัสรู้ด้วยตนเอง และจะอ้างใคร เป็นครูเราเล่า",
  "354": "ธรรมทาน ชนะทานทุกอย่าง รสพระธรรม ชนะรสทุกอย่าง ความยินดีในธรรม ชนะความยินดีทุกอย่าง ความสิ้นตัณหา ชนะทุกข์ทุกอย่าง",
  "355": "โภคทรัพย์ ทำลายคนโง่ แต่ทำลายคนที่ใฝ่แสวงนิพพานไม่ได้ เพราะโลภในโภคทรัพย์ คนโง่ย่อมทำลายคนอื่น และ (ผลที่สุดก็ทำลาย) ตนเอง",
  "356": "หญ้า ทำให้ที่นาเสียหาย ราคะ ทำให้คนเสียหาย ฉะนั้น ทานที่ถวายแก่ผู้ปราศจากราคะ จึงมีผลมหาศาล",
  "357": "หญ้า ทำให้ที่นาเสียหาย โทสะ ทำให้คนเสียหาย ฉะนั้น ทานที่ถวายแก่ผู้ปราศจากโทสะ จึงมีผลมหาศาล",
  "358": "หญ้า ทำให้ที่นาเสียหาย โมหะ ทำให้คนเสียหาย ฉะนั้น ทานที่ถวายแก่ผู้ปราศจากโมหะ จึงมีผลมหาศาล",
  "359": "หญ้า ทำให้ที่นาเสียหาย ความอยาก ทำให้คนเสียหาย ทานที่ถวายแก่ผู้ปราศจากความอยาก จึงมีผลมหาศาล",
  "chap25": "ภิกษุ",
  "360": "สำรวมทางตา เป็นการดี สำรวมทางหู เป็นการดี สำรวมทางจมูก เป็นการดี สำรวมทางลิ้น เป็นการดี",
  "361": "สำรวมทางกาย เป็นการดี สำรวมทางวาจา เป็นการดี สำรวมทางใจ เป็นการดี ภิกษุ ผู้สำรวมทุกทาง ย่อมพ้นจากทุกข์ทั้งปวง",
  "362": "ผู้สำรวมมือ สำรวมเท้า สำรวมวาจา สำรวมกาย ยินดีในการบำเพ็ญวิปัสสนา มีใจเป็นสมาธิ สันโดษอยู่เดียวดาย ได้สมญาว่า ภิกษุ",
  "363": "ภิกษุผู้สำรวมปาก พูดด้วยปัญญา ไม่ถือตัว ชี้แจงตำราและใจความถูกต้อง ถ้อยคำของภิกษุนั้น นับว่าไพเราะแท้",
  "364": "ภิกษุผู้อยู่ในธรรม ยินดีในธรรม พินิจพิจารณาธรรม และรำลึกถึงธรรมเสมอ ย่อมไม่เสื่อมจากพระสัทธรรม",
  "365": "ไม่พึงดูหมิ่นลาภของตน ไม่พึงริษยาลาภคนอื่น เมื่อภิกษุมัวริษยาลาภคนอื่น ใจย่อมไม่เป็นสมาธิ",
  "366": "ภิกษุถึงมีลาภน้อย แต่ไม่ดูหมิ่นลาภของตน มีอาชีวะบริสุทธิ์ ไม่เกียจคร้าน ย่อมได้รับคำชมเชยจากทวยเทพ",
  "367": "ผู้ไม่ยึดมั่นโดยประการทั้งปวง ว่า 'กู' 'ของกู' ไม่ว่าในรูปหรือนาม เมื่อไม่มี ก็ไม่เศร้าโศก เขาผู้นั้นแหละ เรียกได้ว่า ภิกษุ",
  "368": "ภิกษุ ผู้อยู่ด้วยเมตตา เลื่อมใสในพุทธศาสนา พึงลุถึงสภาวะอันสงบ อันเป็นสุข ระงับสังขาร",
  "369": "ภิกษุ เธอจงวิดน้ำออกจากเรือนี้ เมื่อวิดน้ำออกหมดแล้ว เรือจักแล่นเร็ว ทำลายราคะ โทสะ (โมหะ) เสียแล้ว เธอจักไปถึงพระนิพพาน",
  "370": "จงตัดออกห้า ละทิ้งห้า ทำให้เจริญเติบโต อีกห้า พ้นเครื่องผูกพันห้าชนิด ภิกษุจึงได้ชื่อว่า ผู้ข้ามน้ำ",
  "371": "เจริญภาวนาเถิด ภิกษุ อย่ามัวประมาท อย่าปล่อยใจเวียนวนอยู่แต่ในกามคุณ อย่าได้เผลอกลืนกินก้อนเหล็กแดง อย่าปล่อยให้ความทุกข์เผาผลาญเสียเอง แม้มัวคร่ำครวญว่า 'โอ นี่ทุกข์จริงๆ'",
  "372": "เมื่อไม่มีปัญญา ก็ไม่มีความเพ่งพินิจ เมื่อไม่มีความเพ่งพินิจ ก็ไม่มีปัญญา ผู้ใดมีทั้งความเพ่งพินิจ และปัญญา ผู้นั้น นับว่าอยู่ใกล้นิพพาน",
  "373": "ภิกษุผู้ไปสู่ที่สงัด มีใจสงบ เห็นแจ้งพระธรรมโดยชอบ ย่อมได้รับความยินดี ที่สามัญมนุษย์ไม่เคยได้ลิ้มรส",
  "374": "ไม่ว่าเมื่อใด พระอรหันต์พิจารณาเห็น ความเกิดและความดับแห่งขันธ์ทั้งหลาย ท่านย่อมได้ปีติ และปราโมทย์ ซึ่งเป็นสิ่งอมตะสำหรับท่านผู้รู้ทั้งหลาย",
  "375": "สิ่งแรก ที่ภิกษุผู้มีปัญญา จะต้องทำในพระศาสนานี้คือ สำรวมอินทรีย์ มักน้อยสันโดษ ระมัดระวังในวินัยบัญญัติ คบกัลยาณมิตร ผู้ขยันขันแข็ง ผู้มีอาชีวะสะอาด",
  "376": "ภิกษุนั้น พึงรู้จักการปฏิสันถาร ฉลาดในมรรยาทที่พึงประพฤติ เพราะคุณธรรมนั้น เธอจะพึง มีแต่ปราโมทย์ หมดทุกข์ในที่สุด",
  "377": "กอมะลิสลัดช่อบาน ที่เหี่ยวแห้งทิ้งไปฉันใด ภิกษุทั้งหลาย พวกเธอจงสลัด ราคะและโทสะทิ้งไปฉันนั้น",
  "378": "ภิกษุผู้มีกายสงบ มีวาจาสงบ มีใจสงบ ตั้งมั่น ละโลกามิสได้ เรียกว่า ผู้สงบจริง",
  "379": "จงเตือนตนด้วยตนเอง จงพิจารณาตนด้วยตนเอง ภิกษุเอย ถ้าเธอคุ้มครองตนได้ มีสติรอบคอบ เธอจักอยู่เป็นสุข",
  "380": "ตนเป็นที่พึ่งของตนเอง ตนมีทางเดินเป็นของตน เพราะฉะนั้น ควรควบคุมตน เหมือนพ่อค้าม้า ทะนุถนอมม้าดี",
  "381": "ภิกษุผู้มากด้วยปราโมทย์ เลื่อมใสในพระพุทธศาสนา พึงบรรลุถึงสภาวะอันสงบ อันเป็นสุข ระงับสังขาร",
  "382": "ถึงแม้จะเป็นเพียงภิกษุหนุ่ม แต่อุทิศตนแก่พระศาสนา เธอย่อมส่องโลกนี้ให้สว่าง เหมือนพระจันทร์พ้นจากเมฆ",
  "chap26": "พราหมณ์",
  "383": "พราหมณ์เอย ท่านจงพยายามหยุดกระแส (ตัณหา) และบรรเทากามทั้งหลายเสีย พราหมณ์เอย เมื่อท่านรู้ความสิ้นไปแห่งสิ่งปรุงแต่งทั้งหลาย ท่านก็จะรู้สิ่งที่ไม่ปรุงแต่ง (นิพพาน)",
  "384": "เมื่อใดพราหมณ์ข้ามถึงฝั่งโน้น (นิพพาน) ด้วยการปฏิบัติธรรมทั้งสอง (สมถะและวิปัสสนา) เมื่อนั้นเครื่องผูกพันทั้งปวง ของเขาผู้รู้จริงย่อมสิ้นไป",
  "385": "ผู้ใดไม่มีฝั่งนี้ หรือฝั่งโน้น หรือไม่มีทั้งสองฝั่ง ไม่มีความกระวนกระวายใจ เป็นอิสระ ผู้นั้นเราเรียกว่า พราหมณ์",
  "386": "ผู้ใดบำเพ็ญฌาน ปราศจากกิเลส อยู่คนเดียว หมดกิจที่จะพึงทำ หมดอาสวะ ลุถึงจุดหมายปลายทางแล้ว ผู้นั้นเราเรียกว่า พราหมณ์",
  "387": "พระอาทิตย์ สว่างกลางวัน พระจันทร์ สว่างกลางคืน นักรบสง่างามเมื่อสวมเกราะเตรียมรบ พราหมณ์ สง่างามเมื่อเข้าฌาน แต่พระพุทธเจ้าสง่างามทั้งกลางวันกลางคืน",
  "388": "ผู้ที่ชื่อว่าพราหมณ์ เพราะละบาปได้ ชื่อว่าสมณะ เพราะมีจรรยาสงบ ชื่อว่าบรรพชิต เพราะละมลทินได้",
  "389": "ไม่ควรรังแกพราหมณ์ (นักบวช) และพราหมณ์ก็ไม่ควรแสดงความโกรธตอบ คนที่รังแกพราหมณ์ เป็นคนน่าตำหนิ แต่พราหมณ์ผู้โกรธตอบ น่าตำหนิกว่า",
  "390": "ไม่มีอะไรจะดีสำหรับพราหมณ์ เท่ากับหักห้ามใจจากปิยารมณ์ เมื่อใดเขาไม่เบียดเบียนคนอื่น เมื่อนั้น ความทุกข์ก็สงบ",
  "391": "ผู้ใดไม่มีความชั่วทางกาย วาจา ใจ สำรวมระวังทั้งสามทวาร ผู้นั้นเราเรียกว่า พราหมณ์",
  "392": "เมื่อรู้ธรรมที่พุทธเจ้าทรงแสดง จากบุคคลใด ควรเคารพนอบน้อมบุคคลนั้น เหมือนพราหมณ์บูชาไฟ",
  "393": "มิใช่เพราะมุ่นชฏา มิใช่เพราะโคตร มิใช่เพราะกำเนิด (ที่ดี) ที่ทำคนให้เป็นพราหมณ์ ใครก็ตามมีสัจจะและทรงธรรม ย่อมจะบริสุทธิ์ล้ำและเป็นพราหมณ์",
  "394": "เจ้าโง่เอ๋ย ผมยาว หนังสัตว์ จะมีประโยชน์อะไรสำหรับเจ้า ภายนอกเจ้าสะอาดสดใส แต่ภายในเจ้ารกรุงรัง",
  "395": "ผู้ทรงผ้าบังสุกุล ผอมจนเห็นแต่เส้นเอ็น บำเพ็ญฌานในป่าเปลี่ยวคนเดียว เราเรียกว่า พราหมณ์",
  "396": "เพียงเกิดในตระกูลพราหมณ์ หรือมีมารดาเป็นพราหมณ์ เราไม่เรียกเขาว่า พราหมณ์ หากเขายังมีกิเลสอยู่ เขาก็เป็นพราหมณ์แต่ชื่อ ผู้ใดหมดกิเลสไม่ยึดมั่นถือมั่น ผู้นั้นเราเรียกว่า พราหมณ์",
  "397": "ผู้ใดตัดกิเลสเครื่องผูกพันได้หมดสิ้น ไม่หวาดกลัว หมดพันธะ เป็นอิสระจากเครื่องจองจำคือกิเลส ผู้นั้นเราเรียกว่า พราหมณ์",
  "398": "ผู้ที่ตัดชะเนาะ (ความโกรธ) เชือกหนัง (ตัณหา) เชือกป่าน (ความเห็นผิด) พร้อมทั้งอนุสัยกิเลส ถอดลิ่มสลัก (อวิชชา) รู้แจ้งอริยสัจแล้ว เราเรียกว่า พราหมณ์",
  "399": "ผู้ใดไม่โกรธ ทนต่อการด่า และการลงโทษจองจำ มีขันติเป็นกำลังทัพ ผู้นั้นเราเรียกว่า พราหมณ์",
  "400": "ผู้ใดไม่มักโกรธ ทรงศีลพรต หมดกิเลสฝึกฝนตน มีชีวิตอยู่ในโลกนี้เป็นครั้งสุดท้าย ผู้นั้น เราเรียกว่า พราหมณ์",
  "401": "ผู้ใดไม่ติดในกาม เหมือนหยาดน้ำไม่ติดใบบัว และเมล็ดผักกาดไม่ติดปลายเข็ม ผู้นั้นเราเรียกว่า พราหมณ์",
  "402": "ผู้รู้วิธีดับทุกข์ของตนได้ในโลกนี้ หมดภาระแบกหามกิเลส เป็นอิสระจากกิเลส เราเรียกว่า พราหมณ์",
  "403": "ผู้มีปัญญาลึกซึ้ง หลักแหลม ฉลาดเลือกทางผิดทางชอบ บรรลุถึงจุดหมายปลาทางอันอุดม เราเรียกว่า พราหมณ์",
  "404": "ผู้ไม่คลุกคลีกับบุคคลทั้งสองฝ่าย คือคฤหัสถ์และบรรพชิต จรไปคนเดียว ไม่ติดถิ่น มักน้อย เราเรียกว่า พราหมณ์",
  "405": "ผู้งดเบียดเบียนสัตว์อื่น ไม่ว่าเล็กหรือใหญ่ ไม่ฆ่าเอง ไม่สั่งให้คนอื่นฆ่า เราเรียกว่า พราหมณ์",
  "406": "ผู้ไม่ดุร้าย กลางกลุ่มชนผู้ดุร้าย สงบ กลางกลุ่มชนผู้ทารุณ ไม่ยึดมั่นกลางกลุ่มผู้ยึดมั่น เราเรียกว่า พราหมณ์",
  "407": "ความกำหนัด ความขัดเคือง ความหยิ่ง ความดูถูกบุญคุณคนอื่น หมดไปจากผู้ใด เหมือนเมล็ดผักกาด ตกไปจากปลายเข็ม ผู้นั้นเราเรียกว่า พราหมณ์",
  "408": "ผู้พูดถ้อยคำนิ่มนวล แจ่มกระจ่าง สัตย์จริง ไม่กระทบกระทั่งใคร เราเรียกว่า พราหมณ์",
  "409": "ผู้ใดไม่ขโมยของคนอื่น ไม่ว่าสั้นหรือยาว เล็กหรือใหญ่ ดีหรือไม่ดี ผู้นั้นเราเรียกว่า พราหมณ์",
  "410": "ผู้ใดไม่มีความอยาก ในโลกนี้และโลกหน้า หมดกิเลส เป็นอิสระ ผู้นั้นเราเรียกว่า พราหมณ์",
  "411": "ผู้ใดหมดตัณหา หมดสงสัย เพราะรู้แจ้งจริง ลุถึงอมตนิพพานแล้ว ผู้นั้นเราเรียกว่า พราหมณ์",
  "412": "ผู้ละบุญละบาปได้ พ้นกิเลสผูกพัน ไม่โศก ไม่มีกิเลส บริสุทธิ์ เราเรียกว่า พราหมณ์",
  "413": "ผู้บริสุทธิ์ เหมือนจันทร์แจ่ม สงบ ผ่องใส หมดความพอใจในภพ เราเรียกว่า พราหมณ์",
  "414": "ผู้ข้ามสงสารวัฏ และโมหะ อันเป็นทางหล่มที่ข้ามได้แสนยากนี้ ลุถึงฝั่งโน้น เป็นนักกรรมฐาน หมดตัณหา หมดความสงสัย หมดความยึดมั่น บรรลุนิพพาน เราเรียกว่า พราหมณ์",
  "415": "ผู้ละกามารมณ์ ออกบวชไม่มีเรือน หมดความใคร่ในภพ เราเรียกว่า พราหมณ์",
  "416": "ผู้ละตัณหา ออกบวชไม่มีเรือน หมดความอยากในภพ เราเรียกว่า พราหมณ์",
  "417": "ผู้ละเครื่องผูกพัน ทั้งของมนุษย์และเทวดา หมดเครื่องผูกพันทุกชนิด คนเช่นนี้เราเรียกว่า พราหมณ์",
  "418": "ผู้ละความยินดีและความไม่ยินดี เย็นสนิท หมดอุปธิ (กิเลส) อาจหาญ ชนะโลกทั้งมวล เราเรียกว่า พราหมณ์",
  "419": "ผู้รู้จุติ และปฏิสนธิ ของสัตว์ทั้งหลายโดยละเอียด ผู้ไม่ขัดข้อง ไปดี ตรัสรู้ธรรม เราเรียกว่า พราหมณ์",
  "420": "เทวดา คนธรรพ์ และมนุษย์ทั้งหลาย ไม่ทราบทางไปของผู้ใด ผู้เป็นพระอรหันต์ ขีณาสพ ผู้นั้นเราเรียกว่า พราหมณ์",
  "421": "ผู้ไม่มีความยึดถือทั้งเบื้องต้น (อดีต) ท่ามกลาง (ปัจจุบัน) ที่สุด (อนาคต) ปราศจากความยึดมั่นถือมั่น เราเรียกว่า พราหมณ์",
  "422": "มหาฤาษีผู้องอาจ ประเสริฐ แกล้วกล้า ชำนะ ปราศจากตัณหา บริสุทธิ์ ตรัสรู้ธรรม เราเรียกว่า พราหมณ์",
  "423": "มุนี ผู้รู้อดีตชาติของตน เห็นสวรรค์และอบาย ไม่ต้องเกิดอีกต่อไป รู้แจ้งเห็นจริง บำเพ็ญหน้าที่บริบูรณ์แล้ว เราเรียกว่า พราหมณ์"
};
